.setcpu "6502"
.org $2AF8

; ---- module: defs ----

    ; [LADS *=] *= 11000
    ; [LADS .NO]
    ; [LADS .D LADS]
    ; "DEFS" EQUATES AND DEFINITIONS FOR PET/CBM 4.0 BASIC
    ;-------------------- MACHINE SPECIFIC ZERO PAGE EQUATES -----------
    RAMSTART = $28  ; BASIC'S START OF RAM MEMORY POINTER
    BMEMTOP = $34  ; BASIC'S TOP OF RAM MEMORY POINTER
    ST = 150  ; STATUS WORD FOR DISK/TAPE I/O
    LOADFLAG = $9D  ; FLAG WHICH DECIDES LOAD OR VERIFY (0 = LOAD)
    FNAMELEN = $D1  ; LENGTH OF FILENAME FOR OPEN A FILE
    FNAMEPTR = $DA  ; POINTER TO FILENAME LOCATION IN RAM.
    FNUM = $D2  ; CURRENT FILE NUMBER FOR OPEN, GET & PUT CHARS TO DEVICE
    FSECOND = $D3  ; CURRENT SECONDARY ADDRESS FOR OPEN
    FDEV = $D4  ; DEVICE NUMBER (8 FOR COMMODORE DISK)
    CURPOS = 198  ; POSITION OF CURSOR ON A GIVEN SCREEN LINE.
    ;--------------------- LADS INTERNAL ZERO PAGE EQUATES -----------
    TEMP = $FB
    SA = $FD
    MEMTOP = $BB
    PARRAY = $BD
    PMEM = $BF
    ;------------------ MACHINE SPECIFIC ROM EQUATES -----------
    BABUF = $0200  ; BASIC'S INPUT BUFFER
    TOBASIC = $B3FF  ; GO BACK TO BASIC
    KEYWDS = $B0B2  ; START OF KEYWORD TABLE IN BASIC
    OUTNUM = $CF83  ; PRINTS OUT A (MSB), X (LSB) NUMBER
    OPEN = $F563  ; OPENS A FILE (3 BYTES PAST NORMAL OPEN IN ROM).
    CHKIN = $FFC6  ; OPENS A CHANNEL FOR READ (FILE# IN X)
    CHKOUT = $FFC9  ; OPENS CHANNEL FOR WRITE (FILE# IN X)
    CHARIN = $FFE4  ; PULLS IN ONE BYTE
    PRINT = $FFD2  ; SENDS OUT ONE BYTE
    LOAD = $F356  ; LOAD A BASIC PROGRAM FILE (SOURCE CODE FILE) INTO RAM.
    ; (F322 FOR UPGRADE/E172 FOR VIC/E175 FOR 64)
    CLRCHN = $FFCC  ; RESTORES DEFAULT I/O
    CLOSE = $F2E2  ; CLOSE FILE (FILE# IN A)
    STOPKEY = $FFE1  ; TESTS STOP KEY, RETURNS TO BASIC IF PRESSED.
    SCREEN = $8000  ; ADDRESS OF 1ST BYTE OF SCREEN RAM
    ;------------------
    ; [LADS FILE EVAL]

; ---- module: eval ----

    ; "EVAL" MAIN EVALUATION ROUTINE (SIMPLE ASSEMBLER)
    ;---------------------------------------------------------------
START: LDA #0
    LDY #48
STRTLP: STA OP,Y  ;    -- LOOP TO CLEAR FLAGS --
    DEY
    BNE STRTLP  ; --------
    LDA #<START  ; STORE BOTTOM OF LADS INTO TOP OF ARRAY/MEMORY. PROTECT IT.
    STA MEMTOP
    STA BMEMTOP
    STA ARRAYTOP
    LDA #>START
    STA MEMTOP+1
    STA BMEMTOP+1
    STA ARRAYTOP+1  ;--------
    LDA #1  ;    -- SET DEFAULTS --
    ; HERE YOU CAN SET ANY ADDITIONAL DEFAULTS YOU WISH
    STA HXFLAG  ; TURN ON HEX LISTING FLAG
STMO: LDA SCREEN,Y  ;    -- GET SOURCE FILE NAME --
    CMP #32
    BEQ STM1  ; CHECK FOR ANOTHER BLANK
    BCS STM3
    CLC
    ADC #64  ; ADJUST FOR LOW ASCII CHARACTERS
STM3: STA FILEN,Y  ; STORE CHARACTER IN FILENAME BUFFER
    INY
    JMP STMO  ; GET ANOTHER CHARACTER
STM1: STA FILEN,Y  ; CHECK FOR 2ND BLANK
    INY
    LDA SCREEN,Y
    CMP #32  ; IF NO 2ND BLANK SPACE
    BNE STMO  ;    THEN GO BACK FOR MORE NAME (MIGHT BE 2 WORDS)
    DEY
    STY FNAMELEN  ; STORE FILENAME LENGTH
    JSR OPEN1  ; OPEN READ FILE (SOURCE CODE FILE ON DISK)
    ;------------------ RE-ENTRY POINT FOR PASS 2 ------
STORE: JSR GETSA  ; POINT DISKFILE TO 1ST CHARACTER IN SOURCE CODE
    LDA #0
    STA ENDFLAG  ; SET LADS-IS-OVER FLAG TO DOWN
    JSR INDISK  ; GET A SINGLE LINE OF SOURCE CODE
    LDA PASS  ; IF 2ND PASS
    BNE STARTLINE  ;    THEN JUMP OVER PRINTING OF LADS NAME
    JSR PRNTCR  ; PRINT CARRIAGE RETURN
    LDA #230  ; PRINT BLOCK GRAPHICS SYMBOL
    JSR PRINT
    LDA #76  ;    L
    JSR PRINT
    LDA #65  ;    A
    JSR PRINT
    LDA #68  ;    D
    JSR PRINT
    LDA #83  ;    S
    JSR PRINT
    JSR PRNTCR  ; ANOTHER CARRIAGE RETURN
CKHEX: LDA HEXFLAG  ; IF START ADDRESS NUMBER IS HEX, IT'S ALREADY TRANSLATED
    BNE STAR1
    LDA #<LABEL  ; IN THE LABEL BUFFER IS SOMETHING LIKE: *= 864
    STA TEMP  ; PUT THE ADDRESS OF THE BUFFER INTO THE POINTER CALLED TEMP
    LDA #>LABEL
    STA TEMP+1
    JSR VALDEC  ; TURN ASCII NUMBER INTO A TWO-BYTE INTEGER IN "RESULT"
STAR1: LDA RESULT  ;    -- STORE OBJECT CODE'S STARTING ADDRESS IN SA,TA --
    STA SA
    STA TA
    LDA RESULT+1
    STA SA+1
    STA TA+1
    ;----------------    ENTRY POINT FOR EACH NEW LINE OF SOURCE CODE ----
STARTLINE: JSR STOPKEY
    LDA ENDFLAG
    BEQ EVIND
    JMP FINI  ; END LADS ASSEMBLY IF
    ; EITHER THE STOP (BREAK) KEY IS PRESSED OR IF THE ENDFLAG IS UP.
    ;
EVIND: JSR INDISK  ; OTHERWISE GO TO PULL IN A LINE FROM SOURCE CODE
    LDA #0
    STA EXPRESSF  ; SET DOWN THE FLAG THAT SIGNALS A LABEL ARGUMENT LIKE LDA P
    STA BUFLAG  ; SET DOWN THE FLAG THAT SIGNALS # OR ( DURING ARRAY CHECK.
    LDY PASS  ;ON PASS 1, WE DON'T PRINT LINE NUMBERS, ADDR. OR ANYTHING ELSE
    BNE MOREEV
    JMP MOE4
MOREEV: STY LOCFLAG  ; ZERO ADDRESS-TYPE LABEL FLAG (LIKE: LABEL INY)
    ;    THIS IS FOR THE INLINE SUBROUTINE BELOW.
    LDA SFLAG  ; SHOULD WE PRINT TO THE SCREEN
    BEQ MX  ; IF NOT, SKIP THIS PART
    JSR PRNTLINE  ; PRINT LINE NUMBER
    JSR PRNTSPACE  ; PRINT SPACE
    JSR PRNTSA  ; PRINT PC (PROGRAM COUNTER)."SA" IS THE VARIABLE.
    JSR PRNTSPACE
MX: LDA PLUSFLAG  ; DO WE HAVE A + PSEUDO OP
    BEQ MOE4  ; IF NOT SKIP
    JSR MATH  ; IF SO, HANDLE IT IN SUBPROGRAM "MATH"
MOE4: JMP FINDMN  ; LOOK UP MNEMONIC (OR, NOT FINDING ONE, IT'S A LABEL)
    ; -------- EVALUATE ARGUMENT
EVAR: LDA TP
    BEQ TPIJMP  ; CHECK TYPE, IF 0, NO ARGUMENT
    CMP #3  ; IF NOT TYPE 3, THEN CONTINUE EVALUATION
    BNE EVGO
    LDA #1  ; OTHERWISE, REPLACE 3 WITH 1 IN TP (TYPE)
    STA TP
    LDA LABEL+3  ; IS THERE SOMETHING (NOT A ZERO) IN 4TH POSITION
    BNE EVGO  ; EVGO = ARGUMENT (IF NOT, THERE'S NO ARGUMENT,IT'S IMPLIED
    LDA #8  ; OTHERWISE, RAISE OP (OPCODE) BY 8
    CLC
    ADC OP
    STA OP
TPIJMP: JMP TP1  ; AND JUMP TO TYPE 1 (SINGLE BYTE TYPES)
    ;------------------
EQLABEL: LDA PASS  ; MOE4 FOUND IT TO BE A LABEL, NOT A MNEMONIC
    BEQ EQLAB1  ; ON PASS 1 WE DON'T CARE WHICH KIND OF LABEL IT IS SO WE
    LDY #255  ; GO DOWN AND STORE IT IN THE ARRAY (VIA EQLAB1)
EVX1: INY  ; BUT ON PASS 2, WE NEED TO DECIDE IF IT'S A PC ADDRESS TYPE
    LDA LABEL,Y  ; LABEL (LIKE: LABEL INY) OR AN EQUATE TYPE (LABEL = 15)
    BEQ GONOAR  ; SO IN THIS LOOP WE LOOK FOR A BLANK WHILE STORING THE
    STA FILEN,Y  ; LABEL NAME IN THE "FILEN" BUFFER. IF WE FIND A 0, IT'S
    CMP #32  ; A NAKED LABEL (NO ARGUMENT TO IT) WHICH CAUSES US TO PRINT
    BNE EVX1  ;OUT THAT ERROR MESSAGE (AT NOAR, IN EQUATE).OTHERWISE, WE FIND A
    INY  ; BLANK AND FALL THROUGH TO THIS LINE.
    LDA LABEL,Y  ; WE RAISE Y BY 1 AND CHECK FOR AN = SIGN.
    CMP #$3D
    BNE NOTEQ  ; IF NOT, IT'S A PC ADDRESS TYPE (SO SET LOCFLAG)
    JMP INLINE  ; IF SO,WAS = TYPE SO IGNORE IT (ON PASS 2) ----------
NOTEQ: LDX #0
    STX LOCFLAG  ;(SHOWS PRINTOUT TO DO THIS TYPE OF LABEL ON SCREEN/PRINTER)
    TXA  ; PUT A ZERO IN AT THE END OF THE LABEL NAME (AS A DELIMITER)
    STA FILEN,Y  ; NOW WE HAVE TO MOVE THE ARGUMENT PORTION OF THIS LINE
EVX5: LDA LABEL,Y  ; OVER TO THE START OF THE "LABEL" BUFFER FOR FURTHER
    BEQ EVX4  ; ANALYSIS (0 DELIMITER HERE)
    STA LABEL,X  ; WE CAN IGNORE THE PC LABEL (THIS IS PASS 2), BUT WE
    INX  ; NEED TO EVALUATE THE REST OF THE LINE FOLLOWING THAT LABEL.
    INY
    JMP EVX5  ;-------------___---
EVX4: STA LABEL,X
    JMP MOE4  ; JUMP TO CONTINUE EVALUATION
GONOAR: JSR NOAR  ; PRINT NO ARGUMENT MESSAGE (A SPRINGBOARD);----------
EQLAB1: JSR EQUATE  ; PUT LABEL AND IT'S VALUE INTO THE ARRAY (PASS 1)
    JMP MOE4  ; CONTINUE EVALUATION
    ;------------------ TRANSLATE ARGUMENT LABELS INTO NUMBERS
EVEXLAB: LDA BUFFER  ; IS THIS 1ST CHARACTER ALPHABETIC (>64)
    CMP #64
    BCS EVE1  ; IF SO, GO DOWN TO FIND ITS VALUE.
    LDA BUFFER+1  ; IF NOT, IT MUST HAVE BEEN A ( OR # SYMBOL
    INC BUFLAG  ; TO TELL ARRAY THAT ( OR # WAS FOUND (AND TO IGNORE THEM)
EVE1: EOR #$80  ; SET 7TH BIT IN 1ST CHAR. (TO MATCH ARRAY STORAGE METHOD)
    STA WORK  ; SAVE IT HERE TEMPORARILY TO COMPARE WITH ARRAY WORDS
    JSR ARRAY  ; EVAL. EXPRESSION LABEL, SHIFTED 1ST CHAR.
    JMP L340  ; THEN CONTINUE ON WITH EVALUATION (AFTER VALUE IS IN "RESULT")
    ;--------------- IS ARGUMENT NUMERIC OR A LABEL
EVGO: LDY #0
    STY EXPRESSF  ; TURN OFF THE "IT'S A LABEL" FLAG
    ;------------------- SEE CHAPTER 11 FOR DESCRIPTION OF THIS ERROR TRAP
    ;    (TRAP FOR NAKED MNEMONICS ERROR)
    LDA LABEL+3
    CMP #32
    BEQ GVEG
    JMP L700  ; (TEST FOR "INC:" TYPE ERROR)
GVEG: LDA LABEL+4,Y  ; CHECK 5TH CHAR. (LDA NAME OR LDA 25) (THE "N" OR "2")
    CMP #65  ; IF LESS THAN 65 (ASCII FOR "A") THEN IT'S A NUMBER
    BCC EVM02A
    INC EXPRESSF  ; >65 = ALPHABETIC ARG (LABEL) SO RAISE THIS FLAG
EVM02A: STA BUFFER,Y  ; STORE 1ST CHAR. OF ARGUMENT IN "BUFFER" BUFFER
    INY
    LDA LABEL+4,Y  ; LOOK AT 2ND CHAR. IN THE ARGUMENT
    BEQ EVM03  ; IF ZERO, WE'RE AT THE END SO MOVE ON
    STA BUFFER,Y  ; OTHERWISE, STORE 2ND CHAR.
    CMP #65  ; IF LOWER THAN 65, DON'T RAISE LABEL-ARGUMENT FLAG
    BCC EVM02
    INC EXPRESSF  ; IF HIGHER, DO RAISE IT
EVM02: INY  ; NOW MOVE REST OF ARGUMENT UP TO "BUFFER" BUFFER
    LDA LABEL+4,Y  ; LOOP TO MOVE THE ARGUMENT INTO THE BUFFER
    BEQ EVM03  ; EVM03 TAKES OVER AFTER END OF ARGUMENT IS REACHED
    STA BUFFER,Y
    JMP EVM02  ; RETURN FOR MORE ARGUMENT CHARACTERS.
    ;---------------
EVM03: DEY
    STY ARGSIZE  ; REMEMBER NUMBER OF CHARACTERS IN ARGUMENT
    LDA HEXFLAG  ; IF IT'S HEX, INDISK SUBPROGRAM ALREADY TRANSLATED IT FOR US
    BNE L340  ; SO GO ON TO EVALUATE ADDRESS MODE.
    LDA EXPRESSF  ; IF IT'S A LABEL (NOT A NUMBER) THEN GO TO THE ROUTINE
    BNE EVEXLAB  ; WHICH EVALUATES EXPRESSION (ARGUMENT) LABELS, "EVEXLAB"
    ; ---- CALCULATE ARGUMENT'S VALUE (IF IT'S A DECIMAL NUMBER)
    LDA #<BUFFER  ; MAKE "TEMP" POINTER POINT TO "BUFFER"
    STA TEMP
    LDA #>BUFFER
    STA TEMP+1
    LDY #0
    LDA BUFFER  ; IS 1ST CHARACTER HIGHER THAN 48 (ASCII FOR THE NUMBER ZERO)
    CMP #48
    BCS MCAL  ; IF SO, SKIP THIS PART
    CLC  ; IF NOT, THE 1ST CHARACTER MUST BE # OR ( ..... SO WE NEED TO
    INC TEMP  ; MAKE "TEMP" POINT 1 CHARACTER HIGHER IN "BUFFER" TO
    BCC MCAL  ; AVOID HAVING THE ASCII TO INTEGER SUBROUTINE THINK THAT THE
    INC TEMP+1  ; NUMBER STARTS WITH A # OR ( --- THAT WOULD MESS THINGS UP.
MCAL: LDA (TEMP),Y  ; NOW LOOK FOR THE END OF THE NUMBER: -----------
    BEQ MCAL1  ; IT COULD END WITH A 0 (DELIMITER) OR
    CMP #41  ; WITH A ) RIGHT PARENTHESIS OR
    BEQ MCAL1
    CMP #44  ; WITH A , COMMA (AS IN: 15,Y) OR
    BEQ MCAL1
    CMP #32  ; WITH BLANK SPACE (AS IN: #15 ;COMMENT)
    BEQ MCAL1
    INY  ; IF WE'VE NOT YET FOUND ONE OF THESE 4 THINGS, CONTINUE LOOKING
    JMP MCAL  ;----------------------------
MCAL1: PHA  ; SAVE ACCUMULATOR
    TYA
    PHA  ;SAVE Y REGISTER(BY NOW, Y IS POINTING AT THE SPACE JUST AFTER THE #)
    LDA #0  ; PUT DELIMITER ZERO INTO BUFFER JUST FOLLOWING NUMBER.
    STA (TEMP),Y
    JSR VALDEC  ;GO TO THE ASCII-NUMBER-TO-INTEGER-NUMBER-IN-"RESULT" ROUTINE
    PLA  ; RESTORE THE A AND Y REGISTERS
    TAY
    PLA
    STA (TEMP),Y  ; RESTORE "," OR ")" TO THE BUFFER (FOR THE ADDR. ANALYSIS)
    ;
    ;--------- ANALYZE THE ARGUMENT TO DETERMINE ADDRESSING MODE ------
    ;
    ; (THIS ESSENTIALLY AMOUNTS TO MODIFYING THE ORIGINAL OPCODE TO
    ; REFLECT THE CORRECT ADDRESSING MODE. ADJUSTMENTS TO THE OPCODE "OP"
    ; APPEAR RATHER FREQUENTLY FROM HERE ON. THEIR LOGIC WILL NOT BE
    ; COMMENTED. ADDING 4,8,16, OR 24 TO AN "OP" IS BASED ON THE
    ; RELATIONSHIPS WITHIN THE OPCODE TABLE (SEE CHAPTER 9 FOR EXPLANATION)
    ;
L340: LDA BUFFER  ; 1ST CHAR. OF THE ARGUMENT (THE "#" IN LDA #15)
    CMP #35
    BEQ DIMMED  ; # SYMBOL FOUND (SO IMMEDIATE MODE). BRANCH TO SPRINGBOARD
    CMP #40  ; IS IT A "(" LEFT PARENTHESIS. IF SO, GO TO INDIRECT ADDR.
    BEQ INDIR
    LDA TP  ; IS IT A RELATIVE ADDR. MODE (LIKE BNE, BEQ).
    CMP #8
    BEQ REL  ; IF SO, GO TO WHERE THEY ARE HANDLED.
    CMP #3  ; ADD 8 TO OP AT THIS POINT IF IT'S A TYPE 3
    BNE EVM05
    LDA #8
    CLC
    ADC OP
    STA OP
    JMP TP1  ; AND JUMP TO THE SINGLE BYTE TYPES (IMPLIED ADDRESSING)
INDIR: LDY ARGSIZE  ; HANDLE INDIRECT ADDRESSING-------------------
    LDA BUFFER,Y  ; LOOK AT THE LAST CHARACTER IN THE ARGUMENT.
    CMP #41  ; IS IT A ")" RIGHT PARENTHESIS
    BEQ MINDIR  ; IF SO, HANDLE THAT TYPE.
    LDA TP
    CMP #1  ; IF TYPE 1, ADD 16 AT THIS POINT TO OPCODE
    BNE MINDIR
    LDA #16
    CLC
    ADC OP
    STA OP
MINDIR: LDA TP  ; TYPE 6 IS A JUMP INSTRUCTION
    CMP #6
    BEQ JJUMP  ; SO GO TO THE JUMP-HANDLING ROUTINE
    JMP TWOS  ; OTHERWISE, IT MUST BE A 2-BYTE TYPE SO PRINT/POKE IT.;-------
DIMMED: JMP IMMED  ; SPRINGBOARD TO IMMEDIATE MODE TYPES.
    ;------------------------------- HANDLE RELATIVE ADDRESS (BNE) TYPES
REL: LDA PASS  ; ON PASS 1, DON'T BOTHER, JUST INCREASE PC BY 2
    BNE MREL
    JMP TWOS
MREL: SEC  ; ON PASS 2, SUBTRACT PC FROM ARGUMENT TO GET REL. BRANCH
    LDA RESULT
    SBC SA
    PHA  ; SAVE LOW BYTE ANSWER
    LDA RESULT+1
    SBC SA+1
    BCS FOR  ; IF ARGUMENT > CURRENT PC, THEN IT'S A BRANCH FORWARD
    CMP #$FF
    BEQ MPXS
    PLA
    JMP DOBERR
MPXS: PLA  ; OTHERWISE, CHECK FOR OUT OF RANGE BRANCH ATTEMPT
    BPL BERR  ; OUT OF RANGE (PRINT ERROR MESSAGE "BERR")
    JMP RELM  ; AND JUMP TO REL CONCLUSION ROUTINE
FOR: BEQ MPXS1  ; CHECK FORWARD BRANCH OUT OF RANGE
    PLA
    JMP DOBERR
MPXS1: PLA
    BPL RELM  ; WITHIN RANGE-----------------------
BERR: JMP DOBERR  ; PRINT "BRANCH OUT OF RANGE" ERROR MESSAGE
RELM: SEC  ; FINISH UP REL. ADDR. TYPE -------------------
    SBC #2  ; CORRECT FOR THE FACT THAT BRANCHES ARE CALCULATED FROM THE
    STA RESULT  ; INSTRUCTION FOLLOWING THEM: BNE LOOP:LDA 15 WOULD BE
    LDA #0  ;    CALCULATED FROM THE PC OF THE LDA 15
    STA RESULT+1
    JMP TWOS  ; NOW GO TO THE 2-BYTE PRINT/POKE (WITH CORRECT ARGUMENT)
    ;------------------------------- CONTINUE ADDR. MODE ANALYSIS
EVM05: LDY ARGSIZE
    DEY
    LDA BUFFER,Y  ; LOOK AT LAST CHARACTER OF ARGUMENT
    CMP #44  ; IF IT'S NOT A COMMA, THEN THIS MUST BE A JUMP INSTRUCTION
    BNE JJUMP  ; SO GO TO THE JUMP-HANDLING ROUTINE
    INY
    JMP XYTYPE  ; OTHERWISE, IT MUST BE A X OR Y TYPE;---------------
JJUMP: LDA OP  ; HANDLE JMP MNEMONIC
    CMP #76  ; IF THE OPCODE ISN'T 76, IT'S NOT A JUMP
    BNE MEV  ; SO LOOK FOR SOMETHING ELSE
    JMP JUMP  ; NOW SPRINGBOARD TO THE JUMP-HANDLING ROUTINE.----------
MEV: LDA RESULT+1  ; IF HIGH BYTE OF RESULT ISN'T ZERO (ZERO PG. ADDR)
    BNE PREPTHREES  ; THEN GO TO THE 3-BYTE INSTRUCTIONS (LINE 400)
    LDA TP  ; OTHERWISE, IT'S ZERO PAGE MODE
    CMP #6  ; IF HIGHER THAN TYPE 6, IT'S AN ORDINARY 2-BYTE TYPE
    BCS TWOS  ; SO GO THERE.
    CMP #2  ; IF TYPE 2, ALSO GO THERE.
    BEQ TWOS
    LDA #4  ; OTHERWISE, ADD 4 TO OPCODE AND FALL THROUGH INTO TWO-BYTE TYPE
    CLC
    ADC OP
    STA OP
    ;------------------------------- 2 BYTE TYPES (LIKE LDA 12)
TWOS: JSR FORMAT  ; PRINT/POKE OPCODE
    JSR PRINT2  ; THEN PRINT/POKE ARGUMENT
    JMP INLINE  ; AND FINALLY PREPARE TO FETCH NEW LINE OF SOURCECODE (2000)
    ;------------------------------- HANDLE JMP
JUMP: LDY ARGSIZE  ; IS IT JMP 1500 OR JMP (1500)
    LDA BUFFER,Y  ; ) AT THE END PROVES IT'S AN INDIRECT JUMP SO
    CMP #41
    BNE JUMO
    LDA #108  ;    WE MUST CHANGE THE OPCODE FROM 76 TO 108
    STA OP
JUMO: JMP THREES  ; TREAT IT AS A NORMAL 3-BYTE INSTRUCTION
    ;------------------------------- IMMEDIATE ADDRESSING (# TYPE)
IMMED: LDA BUFFER+1
    CMP #$22  ; IS THIS A CHARACTER LOAD PSEUDO-OP LIKE: LDA #"A
    BNE IMMEDX
    LDA BUFFER+2  ; IF SO, PUT THE ASCII CHAR. INTO "RESULT" (ARGUMENT)
    STA RESULT
IMMEDX: LDA TP
    CMP #1
    BNE TWOS  ; IF IT'S TYPE 1, ADJUST OPCODE BY ADDING 8 TO IT.
    LDA #8
    CLC
    ADC OP
    STA OP
    JMP TWOS
    ;------------------------------- 1 BYTE TYPES
TP1: JSR FORMAT  ; JUST POKE OPCODE FOR THESE, THERE'S NO ARGUMENT
    JMP INLINE  ; (LINE 1000)
    ;------------------------------- 3 BYTE TYPES
PREPTHREES: LDA TP  ; SEVERAL OPCODE ADJUSTMENTS (BASED ON TYPE)
    CMP #2
    BEQ PTT
    CMP #7  ; (LINE 430)
    BNE PT1
PTT: LDA OP
    CLC
    ADC #8
    STA OP
    JMP THREES
PT1: CMP #6
    BCS THREES
    LDA OP
    CLC
    ADC #12
    STA OP
THREES: JSR FORMAT  ; PRINT/POKE OPCODE
    JSR PRINT3  ; PRINT/POKE 2 BYTES OF THE ARGUMENT    (3000)
    ;------------------------------------- PREPARE TO GET A NEW LINE
    ;PRINT MAIN INPUT AND COMMENTS, THEN TO STARTLINE
INLINE: LDA PASS  ; ON PASS 1, IGNORE THIS WHOLE PRINTOUT THING.
    BNE NLOX1
    JMP JST
NLOX1: LDA SFLAG  ; LIKEWISE, IF SCREENFLAG IS DOWN, IGNORE.
    BNE NLOX
    JMP JST
NLOX: LDA LOCFLAG  ; ANY PC ADDRESS LABEL TO PRINT
    BNE PRMMX1  ; NO LOC TO PRINT (RVS FLAG USAGE, FOR SPEED)
    LDA PRINTFLAG  ; PRINT TO PRINTER
    BEQ PRMM
    LDA #20
    SEC
    SBC CURPOS  ; SUBTRACT CURRENT CURSOR POSITION
    STA VARA  ; MOVE THE CURSOR TO 20TH COLUMN ON THE SCREEN
    JSR CLRCHN  ; PREPARE PRINTER TO PRINT BLANKS
    LDX #4
    JSR CHKOUT
    LDY VARA
    BPL PRXM1
    LDY #2
    JMP PRMLOP
PRXM1: LDA #32
PRMLOP: JSR PRINT  ;---------------- PRINT BLANKS TO PRINTER
    DEY
    BNE PRMLOP  ; PRINT MORE BLANKS TO PRINTER;---------------
    JSR CLRCHN  ; RESTORE NORMAL I/O
    LDX #1
    JSR CHKIN
PRMM: LDA #20  ; PUT 20 INTO CURRENT SCREEN CURSOR POSITION
    STA CURPOS
    LDA #<FILEN  ; POINT "TEMP" TO PC ADDRESS LABEL FOR PRINTOUT
    STA TEMP
    LDA #>FILEN
    STA TEMP+1
    JSR PRNTMESS  ; PRINT LOCATION LABEL;----------
PRMMX1: LDA #30  ; MOVE CURSOR TO 30TH COLUMN
    SEC
    SBC CURPOS
    STA VARX  ; SAVE OFFSET FROM CURRENT POSITION (30-POSITION) FOR PRINTER
    LDA #30
    STA CURPOS  ; SET SCREEN CURSOR POSITION TO 30
    LDA PRINTFLAG  ; DO WE NEED TO PRINT BLANKS TO THE PRINTER
    BEQ PRMMFIN
    JSR CLRCHN  ; ALERT PRINTER TO RECEIVE BLANKS
    LDX #4
    JSR CHKOUT
    LDY VARX
    BEQ PXMX  ; HANDLE NO BLANKS (IGNORE)
    BMI PXMX  ; HANDLE TOO MANY BLANKS (>127) (IGNORE)
    LDA #32
PRMLOPX: JSR PRINT  ; PRINT BLANKS TO PRINTER FOR FORMATTING--------
    DEY
    BNE PRMLOPX  ; PRINT MORE BLANKS----------
PXMX: JSR CLRCHN  ; RESTORE NORMAL I/O
    LDX #1
    JSR CHKIN  ;-------------------------------------------------
PRMMFIN: JSR PRNTINPUT  ; PRINT MAIN INPUT BUFFER (BULK OF SOURCE LINE)
    LDA BYTFLAG  ; IS THERE A < OR > PSEUDO-OP TO PRINT --------------
    BEQ PRXM  ; HANDLE < AND >
    CMP #1  ; 1 IN BYTFLAG MEANS <
    BNE M05
    LDA #60
    JMP PRMO
M05: LDA #62  ; PRINT >
PRMO: JSR PRINT
    JSR PTP1  ; PRINT > OR <. PTP1 IS TO PRINTER----------
PRXM: LDA BABFLAG  ; IS THERE ANY COMMENT TO PRINT (SOMETHING FOLLOWING ;)
    BEQ RETTX  ; IF NOT, SKIP THIS.
    JSR PRNTSPACE  ; PRINT A SPACE-------- PRINT COMMENTS FIELD ----------
    LDA #59  ; PRINT A SEMICOLON
    JSR PRINT
    LDA #<BABUF  ; POINT "TEMP" TO THE COMMENTS BUFFER "BABUF"
    STA TEMP
    LDA #>BABUF
    STA TEMP+1
    JSR PRNTMESS  ; PRINT WHAT'S IN THE COMMENTS BUFFER
RETTX: JSR PRNTCR  ; PRINT CARRIAGE RETURN
    LDA ENDFLAG  ; IF ENDFLAG IS UP, JUMP TO THE SHUTDOWN ROUTINE
    BNE FINI
JST: JMP STARTLINE  ; OTHERWISE GO BACK UP TO GET THE NEXT SOURCE LINE.
    ;------------------------------------- THE END OF A PASS (1 OR 2)
FINI: LDA PASS
    BNE FIN  ; IF IT'S PASS 2, SHUT EVERYTHING DOWN.
    INC PASS  ; OTHERWISE, CHANGE PASS 1 TO PASS TWO (IN THE FLAG)
    LDA TA  ; PUT THE ORIGINAL START ADDR. INTO THE PC PROGRAM COUNTER (SA)
    STA SA
    LDA TA+1
    STA SA+1
    JSR CLRCHN  ; RESTORE ORDINARY I/0 CONDITIONS
    LDA #1
    JSR CLOSE  ; CLOSE INPUT FILE
    JSR OPEN1  ; OPEN INPUT FILE (POINT IT TO THE 1ST BYTE IN THE FILE)
    JMP STORE  ; PASS 1 FINISHED, START PASS 2 (ENTRY POINT FOR PASS 2) ------
    ;
    ;------------------- SHUT DOWN LADS OPERATIONS AND RETURN TO BASIC -----
FIN: JSR CLRCHN  ; RESTORE NORMAL I/0
    LDA #1
    JSR CLOSE  ; CLOSE SOURCE CODE INPUT FILE
    LDA #2
    JSR CLOSE  ; CLOSE OBJECT CODE OUTPUT FILE (IF ANY)
    LDA PRINTFLAG  ; IS THE PRINTER ACTIVE
    BEQ FINFIN  ; IF NOT, JUST RETURN TO BASIC
    JSR CLRCHN  ; OTHERWISE SHUT DOWN PRINTER, GRACEFULLY.
    LDX #4
    JSR CHKOUT
    LDA #13  ;    BY PRINTING A CARRIAGE RETURN
    JSR PRINT
    JSR CLRCHN
    LDA #4
    JSR CLOSE
FINFIN: JMP TOBASIC  ; RETURN TO BASIC
    ;
    ;-------------------------------------    X OR Y ADDRESSING TYPE
XYTYPE: LDA BUFFER,Y  ; LOOK AT LAST CHAR. IN ARGUMENT
    CMP #88  ; IS IT AN X
    BEQ L720
    DEY  ; OTHERWISE, LOOK AT THE 3RD CHAR. FROM END OF ARGUMENT
    DEY
    LDA BUFFER,Y  ; IS IT A ) RIGHT PARENTHESIS
    CMP #41
    BNE ZEROY  ; IF NOT, IT'S NOT AN INDIRECT ADDR. MODE
    JMP INDIR  ; IF SO, IT IS AN INDIRECT ADDRESSING MODE
ZEROY: LDA RESULT+1  ; CHECK HIGH BYTE OF RESULT (ZERO PG. OR NOT)
    BNE L680  ; ZERO Y TYPE
    LDA TP  ; ADJUST OPCODE BASED ON TYPE
    CMP #2
    BEQ L730
    CMP #5
    BEQ L730
    CMP #1
    BEQ L760
L680: LDA TP
    CMP #1
    BNE L690
    LDA OP
    CLC
    ADC #24
    STA OP
    JMP THREES
L690: LDA TP
    CMP #5
    BEQ M6
    LDA #$31
    JSR P
    JMP L700
M6: LDA OP
    CLC
    ADC #28
    STA OP
    JMP THREES
    ;----------- PRINT A SYNTAX ERROR MESSAGE ------------------
L700: JSR ERRING  ; RING ERROR BELL AND TURN ON REVERSE CHARACTERS
    JSR PRNTLINE  ; PRINT LINE NUMBER
    LDA #<MERROR  ; POINT "TEMP" TO SYNTAX ERROR MESSAGE
    STA TEMP
    LDA #>MERROR
    STA TEMP+1
    JSR PRNTMESS
    JSR PRNTCR  ; PRINT THE MESSAGE
    JMP INLINE  ; GO TO THE GET-THE-NEXT-LINE ROUTINE
    ;------------------------------ CONTINUE ANALYSIS OF ADDR. MODE
L720: LDA RESULT+1  ; MAKE FURTHER ADJUSTMENTS TO OPCODE
    BNE L780  ; NOT ZERO PAGE
L730: LDA TP
    CMP #2
    BNE L740
    LDA #16
    CLC
    ADC OP
    STA OP
    JMP TWOS
L740: CMP #1
    BEQ L759
    CMP #3
    BEQ L759
    CMP #5
    BEQ L759
L750: LDA #$32
    JSR P
    JMP L700
L759: LDA #20
    CLC
    ADC OP
    STA OP
    ; ---------- SEE CHAPTER 11 FOR EXPLANATION OF THIS ERROR TRAP ------
L760: LDA BUFFER+2,Y
    CMP #89
    BNE ML760  ; --- ERROR TRAP FOR LDA (15,Y)
    LDA OP
    CMP #182
    BEQ ML760  ; IS THE MNEMONIC LDX (IF SO, MODE IS CORRECT)
    JMP L680  ; IF NOT, JUMP TO MAKE IT (LDA $0015,Y) ABSOLUTE Y
ML760: JMP TWOS
    ;----------------------------------
L780: LDA TP
    CMP #2
    BNE L790
    LDA #24
    CLC
    ADC OP
    STA OP
    JMP THREES
L790: CMP #1
    BEQ L809
    CMP #3
    BEQ L809
    CMP #5
    BEQ L809
L800: LDA #$33
    JSR P
    JMP L700
L809: LDA #28
    CLC
    ADC OP
    STA OP
    JMP THREES  ;    END OF ADDR. MODE EVALUATIONS AND ADJUSTMENTS
    ;
    ;-------------------- ERROR REPORTING FOR DEBUGGING (PRINTS PC)
P: STA VARA  ; WHEN YOU INSERT A "JSR P" INTO YOUR SOURCE CODE, THIS ROUTINE
    STY VARY  ; WILL PRINT THE PC FROM WHICH YOU JSR'ED.
    STX VARX  ; AFTER AN RTS, THIS WILL REVEAL THE JSR ADDR.
    LDA #$BA  ; PRINT A GRAPHICS SYMBOL TO SIGNAL THAT THE PC IS TO FOLLOW
    JSR PRINT
    PLA  ; SAVE THE RTS ADDRESS (TO KEEP THE STACK INTACT)
    TAX
    PLA
    TAY
    TYA
    PHA
    TXA
    PHA
    TYA
    JSR OUTNUM  ; PRINT THE PC ADDRESS.
    LDA VARA  ; RESTORE THE REGISTERS.
    LDY VARY
    LDX VARX
    RTS
    ; --------------------------
CLEANLAB: LDY #0  ; FILLS MAIN INPUT BUFFER ("LABEL") WITH ZERO. CLEANS IT.
    TYA
CLEMORE: STA LABEL,Y
    INY
    CPY #80
    BNE CLEMORE
    RTS
    ; ---------PRINT BRANCH OUT OF RANGE ERROR MESSAGE--------------
DOBERR: JSR PRNTCR  ; PRINT "BRANCH OUT OF RANGE" ERROR MESSAGE
    JSR ERRING
    JSR PRNTLINE  ; PRINT THE LINE NUMBER
    LDA #<MBOR  ; POINT "TEMP" TO THE ERROR MESSAGE "MBOR"
    STA TEMP  ; (MESSAGE BRANCH OUT OF RANGE, MBOR)
    LDA #>MBOR
    STA TEMP+1
    JSR PRNTMESS  ; PRINT THE MESSAGE
    JSR PRNTCR  ; PRINT A CARRIAGE RETURN AND
    JMP TWOS  ; BUNGLE AS AN ORDINARY 2-BYTE EVENT (TO KEEP PC CORRECT)
    ;----------------------------
    ; [LADS FILE EQUATE]

; ---- module: equate ----

    ; "EQUATE" EVALUATE LABELS
    ; COULD BE EITHER PC (ADDRESS) TYPE OR EQUATE TYPE. STORE IN ARRAY.
    ; FORMAT--NAME/2-BYTE INTEGER VALUE/NAME/2-BYTE VALUE/ETC...
    ;-------------
EQUATE: LDY #255  ; PREPARE Y TO ZERO AT START OF LOOP
EQ1: INY  ; Y GOES TO ZERO 1ST TIME THROUGH LOOP
    LDA LABEL,Y  ; LOOK AT THE WORD, THE LABEL
    BEQ NOAR  ; END OF LINE (SO THERE'S A NAKED LABEL, NOTHING FOLLOWS IT)
    CMP #32  ; FOUND A SPACE, SO RAISE Y BY 2 AND SET LABEL SIZE (LABSIZE)
    BNE EQ1  ; OTHERWISE, KEEP LOOKING FOR A SPACE.
    INY
    INY
    STY LABSIZE
    ;-------------------- LOWER MEMTOP POINTER WITHIN ARRAY (BY LABEL SIZE)
SUBMEM: SEC  ; SUBTRACT LABEL SIZE FROM ARRAY POINTER TO MAKE ROOM FOR LABEL
    LDA MEMTOP
    SBC LABSIZE
    STA MEMTOP
    LDA MEMTOP+1
    SBC #0
    STA MEMTOP+1  ;--------------
    ;SHIFT 7TH BIT OF 1ST CHAR. TO SIGNIFY START OF LABEL'S NAME
    LDY #0
    LDA LABEL,Y
    EOR #$80
    STA (MEMTOP),Y  ; STORE SHIFTED 1ST LETTER
EQ3: INY
    LDA LABEL,Y  ; IF SPACE, STOP STORING LABEL NAME IN ARRAY.
    CMP #32
    BEQ EQ2
    STA (MEMTOP),Y  ; OTHERWISE, PUT NEXT LETTER INTO ARRAY &
    JMP EQ3  ; CONTINUE.
EQ2: INY  ; NOW CHECK FOR = (SIGNIFYING EQUATE TYPE) (LABEL = 15)
    LDA LABEL,Y
    CMP #$3D  ; IF EQUATE TYPE, GO TO FIND ITS VALUE.
    BEQ EQUAL
    DEY  ; OTHERWISE, IT'S PC TYPE (LABEL LDA 15)
    LDA SA  ; SO THE PC VARIABLE (SA) CONTAINS THE VALUE OF THIS LABEL
    STA (MEMTOP),Y  ; STORE IT RIGHT AFTER LABEL NAME WITHIN ARRAY.
    INY
    LDA SA+1
    STA (MEMTOP),Y
    LDX LABSIZE  ; NOW, USING LABELSIZE AS INDEX, ERASE THE PC-TYPE LABEL
    DEX  ;    FROM THE BUFFER. FOR EXAMPLE, (LABEL LDA 15) NOW
    LDY #0  ;    BECOMES (LDA 15). THE LABEL NAME IS COVERED OVER
EQ5: LDA LABEL,X  ; TO PREPARE THE REST OF THE LINE TO BE ANALYZED
    BEQ EQ4  ; NORMALLY BY EVAL.
    STA LABEL,Y
    INX
    INY
    JMP EQ5
EQ4: STA LABEL,Y
    RTS  ; RETURN TO EVAL -------------------------
NOAR: JSR PRNTCR
    JSR PRNTLINE  ;NAKED LABEL FOUND (NO ARGUMENT) SO
    JSR ERRING
    LDA #<NOARG  ; RING BELL AND PRINT NAKED LABEL ERROR MESSAGE.
    STA TEMP
    LDA #>NOARG
    STA TEMP+1
    JSR PRNTMESS
    JSR PRNTCR
    JMP EQRET  ; RETURN TO EVAL-----------------------
    ;
    ;--------------- HANDLE EQUATE TYPES HERE (LABEL = 15)
EQUAL: DEY
    STY LABPTR  ; TELLS US HOW FAR FROM MEMTOP WE SHOULD STORE ARGUMENT VALUE
    LDA HEXFLAG  ; HEX NUMBERS ALREADY HANDLED BY INDISK ROUTINE, SO SKIP OVER.
    BNE FINEQ  ; HEX FLAG UP, SO GO TO EQUATE EXIT ROUTINE BELOW.
    INY  ; OTHERWISE, WE NEED TO FIGURE OUT THE ARGUMENT (LABEL = 15)
    INY  ; THERE ARE THREE CHARS. ( _ ) BETWEEN LABEL & ARGUMENT, SO
    INY  ; INY THRICE.
    STY WORK+1  ; POINT TO LOCATION OF ASCII NUMBER (IN LABEL BUFFER)
    LDA #<LABEL  ; SET UP TEMP POINTER TO POINT TO ASCII NUMBER
    CLC
    ADC WORK+1
    STA TEMP
    LDA #>LABEL
    ADC #0
    STA TEMP+1
    JSR VALDEC  ; CALCULATE ASCII NUMBER VALUE AND STORE IN RESULT
FINEQ: LDY LABPTR  ; STORE INTEGER VALUE JUST AFTER LABEL NAME IN ARRAY
    LDA RESULT
    STA (MEMTOP),Y
    LDA RESULT+1
    INY
    STA (MEMTOP),Y
EQRET: PLA  ;PULL OFF THE RTS (FROM EVAL) AND JUMP DIRECTLY TO INLINE
    PLA  ;    IGNORING ANY FURTHER EVALUATION OF THIS LINE SINCE EQUATE TYPE
    JMP INLINE  ; LABELS ARE FOLLOWED BY NOTHING TO EVALUATE
    ; [LADS FILE ARRAY]

; ---- module: array ----

    ; "ARRAY" LOOKS THROUGH LABEL TABLE AND PUTS VALUE IN RESULT.
    ; (USED IN BOTH PASS 1 AND PASS 2)
ARRAY: LDA ARRAYTOP  ;PUT TOP-OF-ARRAY VALUE INTO THE DYNAMIC POINTER (PARRAY)
    STA PARRAY  ; IN OTHER WORDS, MAKE PARRAY POINT TO THE HIGHEST WORD IN THE
    LDA ARRAYTOP+1  ; LABEL ARRAY
    STA PARRAY+1
    JSR DECPAR
    LDA #$FF  ; SET UP FOR BMI TEST IF NO MATCH FOUND
    STA FOUNDFLAG
STARTLK: SEC  ; START LOOKING FOR LABEL NAME
    LDA MEMTOP  ; CHECK TO SEE IF WE'RE AT THE BOTTOM OF THE ARRAY
    SBC PARRAY
    LDA MEMTOP+1
    SBC PARRAY+1
    BCS ADONE  ; IF SO, CHECK IF WE FOUND THE LABEL (OR FOUND IT TWICE)
    LDX #0  ; SET LABEL NAME SIZE COUNTER TO ZERO
    SEC  ; GO DOWN 2 BYTES IN MEMORY (PAST THE INTEGER VALUE OF A LABEL)
    LDA PARRAY
    SBC #2
    STA PARRAY
    LDA PARRAY+1
    SBC #0
    STA PARRAY+1
    LDY #0
    ;--------------------------
LPAR: LDA (PARRAY),Y  ; LOOK FOR A 7TH BIT SET (START OF LABEL NAME)
    BMI FOUNDONE  ; IF YES, WE'VE GOT TO THE START OF A NAME.
    LDA PARRAY  ; OTHERWISE GO DOWN 1 BYTE IN ARRAY
    BNE MDECX
    DEC PARRAY+1
MDECX: DEC PARRAY
    INX  ; INCREASE LABEL NAME SIZE COUNTER
    JMP LPAR
    ;-----------------------
FOUNDONE: LDA PARRAY  ; WE'VE LOCATED A LABEL NAME IN THE ARRAY
    STA PT  ; REMEMBER IT'S STARTING LOCATION
    LDA PARRAY+1
    STA PT+1
    LDA (PARRAY),Y
    CMP WORK  ; COMPARE THE 1ST LETTER WITH THE 1ST LETTER OF THE TARGET WORD
    BEQ LKMORE  ; LOOK MORE CLOSELY AT THE WORD, IF 1ST LETTER MATCHED
    JMP STARTOVER  ; IF IT DIDN'T MATCH, GO DOWN IN THE TABLE & FIND NEXT WORD.
    ;---------------------------
LKMORE: INX  ; RAISE LENGTH COUNTER BY 1
    STX WORK+1  ; REMEMBER IT
    LDX #1
    LDA BUFLAG  ;THIS MEANS THAT # OR ( COME BEFORE THE NAME IN THE BUFFER
    BEQ LKM1  ; IF THEY DON'T WE DON'T NEED TO RAISE Y IN ORDER TO IGNORE THEM
    INY
    JSR DECPAR  ; LOWER THE INDEX TO COMPENSATE FOR THE INY
    ;
LKM1: INY
    LDA BUFFER,Y  ; CHECK BUFFER-HELD LABEL
    BEQ FOUNDIT  ; IF WE'RE AT THE END OF THE WORD (0), THEN WE'VE FOUND A MATCH
    CMP #48  ; OR THERE'S A MATCH IF IT'S A CHARACTER LOWER THAN ASCII 0 (,OR+)
    BCC FOUNDIT
    ; NOT YET THE END OF THE "BUFFER" HELD LABEL
    INX
    CMP (PARRAY),Y  ; IF ARRAY WORD STILL AGREES WITH BUFFER WORD, THEN
    BEQ LKM1  ; CONTINUE LOOKING AT THESE WORDS
    ;--------------------------- NO MATCH, SO LOOK AT NEXT WORD DOWN -----
STARTOVER: LDA PT  ; PUT PREVIOUS WORD'S START ADDR. INTO POINTER
    STA PARRAY
    LDA PT+1
    STA PARRAY+1
    JSR DECPAR  ; LOWER POINTER BY 1 (STARTLK WILL LOWER IT ALSO, BELOW VALUE)
    JMP STARTLK  ; TRY ANOTHER WORD IN THE ARRAY
    ;-----------------------
ADONE: LDA FOUNDFLAG
    BMI AD1  ; DIDN'T FIND THE LABEL
    RTS  ; ALL IS WELL. RETURN TO EVAL.
AD1: LDA PASS
    BNE ADlX  ; 2ND PASS-- GO AHEAD AND PRINT ERROR MESSAGE
    BEQ ADONE1  ; ON 1ST PASS, MIGHT NOT YET BE DEFINED (RAISE INCSA/2S OR 3S)
ADlX: JSR ERRING  ; LABEL NOT IN TABLE. (TREAT IT AS A 2-BYTE ADDRESS)
    JSR PRNTLINE
    JSR PRNTSPACE
    LDA #<NOLAB
    STA TEMP
    LDA #>NOLAB
    STA TEMP+1
    JSR PRNTMESS  ; RING BELL AND PRINT NOT FOUND MESSAGE
    JSR PRNTCR
ADONE1: PLA
    PLA  ;
    LDA OP
    AND #31
    CMP #16
    BEQ AD02  ; CHECK IF BRANCH INSTRUCT.
    LDA BYTFLAG
    BNE AD02  ; < OR > PSEUDO
    JMP THREES
AD02: JMP TWOS
    ;
FOUNDIT: CPX WORK+1  ;CHECK LABEL LENGTH AGAINST TARGET WORD LENGTH
    BEQ FOUNDF  ; THEY MUST EQUAL TO SIGNIFY A MATCH. (PRINT/PRIN WOULD FAIL)
    JMP STARTOVER  ; FAILED MATCH
FOUNDF: INC FOUNDFLAG  ; RAISE FLAG TO ZERO (FIRST MATCH)
    BEQ FOFX  ; IF HIGHER THAN 0, PRINT DUPLICATION LABEL ERROR MESSAGE
    JSR DUPLAB
FOFX: LDY WORK+1
    LDA BUFLAG  ; COMPENSATE FOR # AND
    BEQ FOF
    INY
FOF: LDA (PARRAY),Y  ; PUT TABLE LABEL'S VALUE IN RESULT
    STA RESULT
    INY
    LDA (PARRAY),Y
    STA RESULT+1
    LDA BYTFLAG
    BEQ CMPMO  ; IS IT > OR < PSEUDOPRINT
    CMP #2
    BNE AREND
    LDA RESULT+1  ; STORE HIGH BYTE INTO LOW BYTE
    STA RESULT
CMPMO: LDA PLUSFLAG  ; DO ADDITION + PSEUDO OP
    BEQ AREND
    CLC  ; ADD THE + NUMBER "ADDNUM" TO RESULT
    LDA ADDNUM
    ADC RESULT
    STA RESULT
    LDA ADDNUM+1
    ADC RESULT+1
    STA RESULT+1
AREND: LDA PASS  ; ON 2ND PASS, CHECK FOR DUPS
    BNE ARENX
    RTS  ; GO BACK TO EVAL
ARENX: JMP STARTOVER  ; ON PASS 2, LOOK FOR DUPS (SO CONTINUE IN ARRAY)
    ;-----------------------------
DECPAR: LDA PARRAY  ; LOWER ARRAY POINTER BY 1
    BNE MDEC
    DEC PARRAY+1
MDEC: DEC PARRAY
    RTS
    ; -----------------
DUPLAB: JSR ERRING  ; RING BELL AND PRINT DUP LABEL MESSAGE
    LDA #<MDUPLAB
    STA TEMP
    LDA #>MDUPLAB
    STA TEMP+1
    JSR PRNTMESS
    JSR PRNTCR
    RTS  ;-------------------------------------------
    ; [LADS FILE OPEN1]

; ---- module: open1 ----

    ; "OPEN1"  OPEN 1,8,3,"WHATEVER NAME FROM SCREEN"
    ; OPEN A FILE ON DISK (THIS TYPE OF FILE IS READ FROM)
    ;------------------
OPEN1: JSR CLRCHN  ;RESTORE NORMAL I/0 (OUTPUT TO SCREEN, INPUT FROM KEYBOARD)
    LDA #1  ; CLOSE DOWN DISK FILE CHANNEL #1
    JSR CLOSE  ; (WE'RE GOING TO REOPEN IT NOW, BUT WE CLOSE IT FIRST)
    LDA #1
    STA FNUM  ;    FILE#
    LDA #8
    STA FDEV  ;    DEVICE NUMBER.
    LDA #3
    STA FSECOND  ;    SECONDARY ADDR.
NAMEAD: LDA #<FILEN  ; SET POINTER TO FILE NAME BUFFER (FILEN) IN LADS.
    STA FNAMEPTR  ;POINTER TO FILENAME ADDR.
    LDA #>FILEN
    STA FNAMEPTR+1
    JSR OPEN  ; ROUTINE WITHIN BASIC THAT OPENS UP A NEW FILE
    RTS
    ;------------------------
    ; OPEN 2,8,2,"NAME" (OPENS DISK PROGRAM FILE FOR WRITING OBJECT CODE)
    ;------------------------
OPEN2: LDA #2  ; SEE DEFINITIONS ABOVE (SAME SETUP)
    STA FNUM
    LDA #8
    STA FDEV
    LDA #2
    STA FSECOND
    LDA #<FILEN
    STA FNAMEPTR  ; POINTER TO FILENAME ADDR.
    LDA #>FILEN
    STA FNAMEPTR+1
    JSR OPEN
    JSR CLRCHN
    RTS
    ;-------------------------
    ; OPEN 4,4    (OPENS FILE TO PRINTER)
    ;------------------------
OPEN4: LDA #4  ; SAME FORMAT, EXCEPT FNAMELEN
    STA FNUM
    LDA #4
    STA FDEV
    LDA #0  ; THERE IS NO FILE NAME SO SET FILENAME LENGTH TO ZERO.
    STA FNAMELEN
    JSR OPEN
    JSR CLRCHN
    RTS
    ;-------------------------
    ; LOAD "NAME" (LOADS A PROGRAM FILE, A SOURCE CODE FILE INTO RAM)
    ;------------------------
LOAD1: JSR CLRCHN  ;RESTORE NORMAL I/O
    LDA #0
    STA LOADFLAG  ; LOAD/VERIFY FLAG
    STA ST  ; THE STATUS BYTE
    LDA #8
    STA FDEV  ;    DEVICE NUMBER.
    LDA #<FILEN  ; SET POINTER TO FILENAME BUFFER (FILEN) IN LADS.
    STA FNAMEPTR  ;POINTER TO FILENAME ADDR.
    LDA #>FILEN
    STA FNAMEPTR+1
    JSR LOAD  ; ROUTINE WITHIN BASIC THAT LOADS IN A PROGRAM
    JSR CLRCHN
    LDA RAMSTART
    STA PMEM
    LDA RAMSTART+1
    STA PMEM+1
    RTS
    ; [LADS .FILE FINDMN]

; ---- module: findmn ----

    ; "FINDMN" -- LOOKS THROUGH MNEMONICS FOR MATCH TO LABEL.
    ; WE JMP TO THIS FROM EVAL. & JMP BACK TO 1 OF 2 LOCATIONS (JMP FOR SPEED)
FINDMN: LDY #0
    LDX #255  ; PREPARE X TO GO TO ZERO AT START OF LOOP
LOOP: INX  ; X RAISED TO ZERO AT START OF LOOP
    LDA MNEMONICS,Y  ; LOOK IN TABLE OF MNEMONICS
    CMP LABEL  ; COMPARE IT TO 1ST CHAR. OF WORD IN LABEL BUFFER
    BEQ MORE  ; IF =, COMPARE 2ND LETTERS OF TABLE VS. BUFFER
    INY  ; OTHERWISE GO UP THREE IN THE TABLE TO FIND THE NEXT MNEMONIC
    INY
    INY
    CPX #57  ; HAVE WE CHECKED ALL 56 MNEMONICS.
    BNE LOOP  ; IF NOT, CONTINUE TRYING TO FIND A MATCH
NOMATCH: JMP EQLABEL  ; DIDN'T FIND A MATCH (SO GO BACK TO EVAL)
MORE: INY  ; COMPARE 2ND LETTER
    LDA MNEMONICS,Y
    CMP LABEL+1
    BEQ MORE1  ; IF =, GO ON TO COMPARE 3RD AND FINAL LETTER
    INY
    INY
    BNE LOOP  ; 2ND LETTER DIDN'T MATCH, TRY NEXT MNEMONIC (Y <> 0)
    BEQ NOMATCH  ; IF Y = 0, WE'VE GONE PAST TABLE (RETURN TO EVAL)
MORE1: INY  ; COMPARE 3RD LETTER
    LDA MNEMONICS,Y
    CMP LABEL+2
    BEQ FOUND  ; IF 3RD LETTERS ARE =, WE'VE FOUND OUR MATCH
    INY
    BNE LOOP  ; OTHERWISE TRY NEXT MNEMONIC
    BEQ NOMATCH
FOUND: LDA LABEL+3  ; THE 4TH CHAR. MUST BE A BLANK FOR THIS TO BE A MNEMONIC
    CMP #32
    BEQ FO1  ; IF SO, STORE DATA ABOUT THIS MNEMONIC & RETURN TO EVAL.
    CMP #0  ; OR IF END OF LINE, IT WOULD BE AN IMPLIED ADDR. MNEMONIC LIKE INY
    BNE NOMATCH  ; OTHERWISE, NO MATCH FOUND (IT'S NOT A MNEMONIC).
FO1: LDA TYPES,X  ; STORE ADDR. TYPE.
    STA TP
    LDY OPS,X  ; STORE OPCODE
    STY OP
END: JMP EVAR  ; MATCH FOUND SO JUMP TO EVAR ROUTINE IN EVAL
    ; [LADS .FILE GETSA]

; ---- module: getsa ----

    ; "GETSA" GET STARTING ADDRESS FROM DISK (LEAVES DISK POINTING AT-
    ;    *= THIS SPACE (START ADDRESS)
    ;    (EXPECTS FILE #1 TO BE ALREADY OPENED).
    ; -------------------------
GETSA: LDX #1  ; SET UP INPUT CHANNEL FOR A DEVICE (TO GET BYTES)
    JSR CHKIN  ; BASIC'S ROUTINE
    LDX #6  ; WE NEED TO THROW AWAY THE 1ST 6 BYTES ON A DISK FILE (LINE LINK,
LSA: JSR CHARIN  ; LINE #, AND 2 BYTES) (CHARIN IS "GET BYTE")
    DEX  ; COUNT DOWN UNTIL WE'VE PULLED OFF THE
    BNE LSA  ; 1ST 6 BYTES ... THEN------------------
    JSR CHARIN  ; PULL IN NEXT BYTE
    CMP #172  ; IS IT THE * SYMBOL
    BEQ MSA  ; IF SO, GO BACK TO CALLER (EVAL SUBPROGRAM CALLS GETSA)
    LDA #<MNOSTART  ; OTHERWISE, PRINT ERROR MESSAGE WHICH
    STA TEMP  ; SAYS "NO START ADDRESS". POINT TO THIS ERROR MESSAGE IN
    LDA #>MNOSTART  ; THE POINTER,"TEMP," AND PRINT THE MESSAGE (PRNTMESS)
    STA TEMP+1  ; (NOTE: THIS NO-START-ADDRESS CONDITION OCCURS 2 WAYS: EITHER
    JSR PRNTMESS  ; YOU FORGOT TO WRITE ONE OR YOU GAVE THE WRONG FILE NAME)
    JMP FIN  ; GO BACK TO BASIC VIA THE SHUTDOWN ROUTINE WITHIN EVAL;-------
MSA: RTS
    ; [LADS .FILE VALDEC]

; ---- module: valdec ----

    ; "VALDEC" TRANSLATE ASCII INPUT TO A TWO-BYTE INTEGER IN RESULT
    ;
    ; SETUP/TEMP MUST POINT TO ASCII NUMBER (WHICH ENDS IN ZERO).
    ; RESULTS/ RESULT HOLDS 2-BYTE RESULT
    ; --------------------------
VALDEC: LDY #0
    ; READ ASCII FROM LEFT TO RIGHT--INCREMENTING Y --(TO FIND LENGTH)
VGETZERO: LDA (TEMP),Y
    BEQ VZERO  ; 0 DELIMITER FOUND
    INY
    JMP VGETZERO  ;--------------- (FOR EXAMPLE, ASSUME ASCII IS "15")
VZERO: STY VREND  ; SAVE LENGTH OF ASCII NUMBER (IN THE EXAMPLE, LEN = 2)
    DEY
    LDA #0  ; CLEAN "RESULT" VARIABLE (SET TO 0)
    STA RESULT
    STA RESULT+1
    LDX #1  ; USE "X" VARIABLE AS A MULTIPLY-X10-HOW-MANY-TIMES COUNTER
    STX VARX
VALLOOP: LDA (TEMP),Y  ; LOAD IN THE RIGHTMOST ASCII CHARACTER (EX: "5")
    AND #$0F  ; AS ASCII, 5 = $35. 0 STRIP OFF THE 3, LEAVING THE 5.
    STA RADD  ; STORE IN MULTIPLICATION REGISTER
    STA TSTORE  ; STORE IN "REMEMBER IT" REGISTER
    LDA #0  ; PUT 0 IN BOTH THESE REGISTERS (IN THEIR HIGH BYTES)
    STA RADD+1
    STA TSTORE+1  ;----------------- MULTIPLY X10 AS MUCH AS NECESSARY------
VLOOP: DEX  ; LOWER THE COUNTER. (IN THE EXAMPLE, X NOW = 0 FOR 1ST CHAR)
    BEQ VGOON  ; SO WE DON'T JSR TO THE X10 SUBROUTINE IN THIS CASE)
    JSR TEN  ; OTHERWISE,WE'D MULTIPLY THE NUMBER X10 AS MANY TIMES AS NECESSARY
    LDA RADD  ; MOVE RESULT OF MULTIPLICATION INTO STORAGE REGISTER
    STA TSTORE
    LDA RADD+1
    STA TSTORE+1  ; SAVING RESULTS OF MOST RECENT MULTIPLICATION
    JMP VLOOP  ; CONTINUE MULTIPLYING X10 UNTIL X IS DOWN TO ZERO.--------
VGOON: INC VARX  ; RAISE X BY 1 (SINCE WE'RE MOVING LEFT AND EACH NUMBER WILL
    ;        BE 10X THE ONE TO ITS RIGHT).
    LDX VARX
    JSR VALADD  ; ADD RADD TO RESULT (ADD IN RESULTS OF THE MULTIPLICATION)
    DEY  ; MOVE INDEX OVER BY 1 (TO POINT TO NEXT ASCII CHAR. TO THE LEFT)
    DEC VREND  ; LOWER LENGTH POINTER. IF IT'S NOT YET ZERO, THEN
    BNE VALLOOP  ; CONTINUE PROCESSING THIS ASCII NUMBER
    RTS  ; OTHERWISE RETURN TO CALLER.
    ;---------------    MULTIPLY BY 10
TEN: CLC
    ASL RADD  ;    MULTIPLY RADD X 4
    ROL RADD+1
    ASL RADD
    ROL RADD+1  ;---------------
    CLC
    LDA TSTORE  ;PULL OUT ORIGINAL NUMBER AND ADD IT TO RESULT OF X4 (GIVING X5)
    ADC RADD
    STA RADD
    LDA TSTORE+1
    ADC RADD+1
    STA RADD+1  ;------------ NOW, MULTIPLY X2.    ((N*4+N)*2) IS N*10
    ASL RADD
    ROL RADD+1
    RTS
    ;------------- ADD RESULTS OF THE MULTIPLICATION TO THE INTEGER ANSWER
VALADD: CLC
    LDA RADD
    ADC RESULT
    STA RESULT
    LDA RADD+1
    ADC RESULT+1
    STA RESULT+1
    RTS
    ; [LADS .FILE INDISK]

; ---- module: indisk ----

    ; "INDISK" MAIN GET-INPUT-FROM-DISK ROUTINE
    ;SETUP/EXPECTS DISK TO POINT TO 1ST CHAR IN A NEW LINE (OR BEYOND COLON)
    ;RESULTS/EITHER FLAGS END OF PROG. OR FILLS LABEL+ WITH LINE OF CODE
    ;------------------
INDISK: JSR CLEANLAB  ; FILL LABEL WITH ZEROS (ROUTINE IN EVAL)
    LDY #0
    STY HEXFLAG  ; PUT HEXFLAG DOWN
    STY BABFLAG  ; PUT COMMENTS FLAG DOWN
    STY BYTFLAG  ; PUT FLAG SHOWING < OR > DOWN
    STY PLUSFLAG  ; PUT ARITHMETIC PSEUDO OP (+) FLAG DOWN
    LDA COLFLAG  ; IF THERE WAS A COLON JUST PRIOR TO THIS, REMOVE ANY BLANKS
    BNE NOBLANKS  ; (THIS TAKES CARE OF: INY: LDA 15:    LDX 17 TYPE ERRORS)
    JSR CHARIN  ; OTHERWISE, PULL IN THE 1ST CHARACTER (FROM DISK OR RAM)
    STA LINEN  ; STORE LOW BYTE OF LINE NUMBER
    JSR CHARIN
    STA LINEN+1  ; STORE HIGH BYTE OF LINE NUMBER
NOBLANKS: JSR CHARIN  ; ROUTINE TO ELIMINATE BLANKS FOLLOWING A COLON
    BNE COOLOOK
    JSR ENDPRO  ; THIS HANDLES COLONS PLACED ACCIDENTALLY AT END OF LINE
    PLA
    PLA
    JMP STARTLINE
COOLOOK: CMP #32  ; (OR FOLLOWING A LINE NUMBER)
    BEQ NOBLANKS  ;--------------------------
    JMP MOI1  ; SKIP TO CHECK FOR COLON (IT'S EQUIVALENT TO AN END OF LINE 0)
STINDISK: JSR CHARIN  ; ENTRY POINT WITHIN LINE (NOT AT START OF LINE)
MOINDI: BNE MOI1  ; IF NOT ZERO, LOOK FOR COLON
    JMP ENDPRO  ; FOUND A 0 END OF LINE. CHECK FOR END OF PROGRAM (3 ZEROS)
MOI1: CMP #58  ; IS IT A COLON
    BNE XMO1  ; IF NOT, CHECK FOR SEMICOLON
    JMP COLON  ; FOUND A COLON
XMO1: CMP #59  ; IS IT A SEMICOLON
    BNE COMOA  ; IF NOT CONTINUE ON
    STY VARA  ; FOUND A SEMICOLON (REM)
    LDA PRINTFLAG  ; IF PRINTOUT NOT REQUESTED, THEN DON'T STORE THE REMARKS
    BEQ PULLRX
    STA BABFLAG  ; SET UP PRINT COMMENTS FLAG (A MUST BE > 0 AT THIS POINT)
    LDA VARA  ; OTHERWISE, CHECK Y (SAVED ABOVE).    IF ZERO, IS A SEMICOLON AT
    BEQ PUX  ; START OF THE LINE (NO LABELS OR MNEMONICS, JUST A BIG COMMENT)
    JSR PULLREST  ; OTHERWISE SAVE COMMENTS FOLLOWING THE SEMICOLON
    JMP MPULL  ; AND THEN RETURN TO EVAL ---------------------------
PUX: JSR CHARIN  ; PUT NON-COMMENT DATA INTO LABEL BUFFER
    BEQ PUX1  ; END OF LINE, SO EXIT
    CMP #127  ; 7TH BIT NOT SET (SO IT'S NOT A KEYWORD IN BASIC)
    BCC PUX2
    JSR KEYWORD  ; IT IS A KEYWORD, SO EXTEND IT OUT AS AN ASCII WORD
PUX2: STA LABEL,Y  ; PUT THE CHAR. INTO THE MAIN BUFFER
    INY
    JMP PUX  ; RETURN TO LOOP FOR MORE CHARACTERS---------------------
PUX1: JSR PRNTLINE  ; PRINT THE LINE NUMBER
    JSR PRNTSPACE  ; PRINT A SPACE
    JSR PRNTINPUT  ; PRINT THE CHARACTERS IN THE LABEL BUFFER (MAIN BUFFER)
    JSR PRNTCR  ; PRINT A CARRIAGE RETURN
    LDA #0  ; SET A VARIABLE TO ZERO TO SIGNIFY NOTHING FOR EVAL TO EVALUATE
    STA VARA
    JMP MPULL  ; GO TO EXIT ROUTINE--------------------------------
PULLREST: STA BABFLAG  ; PUT REMARKS INTO BABUF (BUFFER FOR COMMENTS)
    ;    THIS ROUTINE REMOVES (AND SAVES) COMMENTS
    STA VARA  ; SET A VARIABLE TO SIGNIFY NOTHING FOR EVAL TO EVALUATE
    LDY #0  ; SET OFFSET TO BABUF BUFFER FOR FILLING WITH COMMENTS
PAX1: JSR CHARIN  ; GET CHARACTER
    BNE PAX  ; IF NOT ZERO, CONTINUE
    STA BABUF,Y  ; OTHERWISE, WE'RE AT THE END OF THE COMMENT
    LDY VARA
    RTS  ; Y MUST HOLD OFFSET FOR ZERO FILL (ENDPRO) -----------------
PAX: BPL PAXA  ; NOT A KEYWORD (7TH BIT NOT SET)
    JSR KEYWAD  ; OTHERWISE, EXTEND KEYWORD INTO AN ASCII STRING
PAXA: STA BABUF,Y  ; STORE CHAR. IN REMARK BUFFER
    INY
    JMP PAX1  ; RETURN TO LOOP TO GET ANOTHER CHARACTER--------------
PULLRX: JSR CHARIN  ; JUST PULL IN REMARK CHARACTERS, IGNORING THEM
    BEQ MPULL  ; LOOKING FOR THE END OF LINE ZERO
    JMP PULLRX  ;--------------------------
MPULL: JSR ENDPRO  ; CHECK FOR END OF PROGRAM AND THEN
    LDA VARA  ; SEE IF Y = 0. IF SO, THE SEMICOLON WAS AT THE START OF A LINE
    BNE MPULL1
    PLA  ; Y = 0 SO JUMP BACK TO EVAL TO PREPARE TO GET NEXT LINE
    PLA
    JMP STARTLINE  ; SEMI @ START SO RETURN TO EVAL TO GET NEXT LINE---------
MPULL1: RTS  ; SEMICOLON, BUT NOT AT START OF LINE (RETURN TO CALLER)
COMOA: CMP #177  ;------------------ CHECK FOR OTHER ODD CHARACTERS
    BEQ HI  ; FOUND >
    CMP #179
    BEQ LO  ; FOUND <
    CMP #170
    BNE COMO
    INC PLUSFLAG  ; FOUND +
COMO: CMP #172
    BNE COM01
    JMP STAR  ; FOUND
COM01: CMP #46
    BEQ PSEUDOO  ; FOUND PSEUDO-OP
    CMP #36
    BEQ HEXX  ; FOUND HEX NUMBER
    CMP #127  ; NOT A KEYWORD (7TH BIT NOT UP)
    BCC ADDLAB
    JSR KEYWORD  ; FOUND KEYWORD, SO EXTEND IT INTO AN ASCII STRING
ADDLAB: STA LABEL,Y  ; PUT THE CHARACTER INTO THE MAIN BUFFER AND
    INY  ; RAISE THE POINTER AND
    JMP STINDISK  ; RETURN TO GET ANOTHER CHARACTER (BUT NOT A LINE NUMBER)
    ;----------------------
COLON: STA COLFLAG  ; SIGNIFY COLON BY SETTING COLFLAG
    RTS  ;----------------------
PSEUDOO: JMP PSEUDOJ  ; SPRINGBOARD TO PSEUDO-OP HANDLING ROUTINES
HEXX: STA LABEL,Y  ; SPRINGBOARD TO HEX NUMBER TRANSLATOR
    INY
    JMP HEX
    ;-------- TRANSLATE. A SINGLE-BYTE KEYWORD TOKEN INTO ASCII STRING
KEYWORD: SEC  ; FIND NUMBER OF KEYWORD (IS IT 1ST, 5TH, OR WHAT)
    SBC #$7F
    STA KEYNUM  ; STORE NUMBER (POSITION) IN BASIC'S KEYWORD TABLE
    LDX #255
SKEY: DEC KEYNUM  ; REDUCE NUMBER BY 1 (WHEN ZERO, WE'VE FOUND IT IN TABLE)
    BEQ FKEY  ; AND WE EXIT THIS SEARCH ROUTINE AND STORE THE ASCII WORD
KSX: INX  ; BRING X UP TO ZERO AT START OF LOOP
    LDA KEYWDS,X  ; LOOK AT CHAR. IN BASIC'S TABLE.
    BPL KSX  ;DID NOT FIND A SHIFTED BYTE
    BMI SKEY  ; DID FIND START-OF-KEYWORD SHIFTED CHARACTER -------------
FKEY: INX  ; STORE THE KEYWORD INTO LADS' MAIN BUFFER (LABEL)
    LDA KEYWDS,X
    BMI KSET  ; A SHIFTED CHAR. INDICATES END OF KEYWORD, START OF NEXT KEYWORD
    STA LABEL,Y  ; PUT CHAR. INTO LADS' BUFFER
    INY
    JMP FKEY  ; LOOP AGAIN FOR NEXT CHAR.---------------------
KSET: AND #$7F
    RTS  ; CLEAR OUT BIT 7 AND RETURN TO CALLING ROUTINE
    ;------------------ HANDLE > AND < PSEUDO-OPS
HI: LDA #2  ;    THE BYTFLAG HAS 3 POSSIBLE STATES:
    STA BYTFLAG  ;    0 = LINE DOESN'T CONTAIN A > OR < PSEUDO
    JMP STINDISK  ;    1 = < (LOW BYTE) TYPE
LO: LDA #1  ;    2 = > (HIGH BYTE) TYPE
    STA BYTFLAG  ;    (ACTION IS TAKEN ON THIS PSEUDO-OP WITHIN THE
    JMP STINDISK  ;    EQUATE SUBPROGRAM). 0 WE FETCH THE NEXT CHAR.
    ;------------------ HANDLE THE *= PSEUDO-OP (CHANGE THE PC)
STAR: JSR STINDISK
    ;LDA PASS; ON PASS 1, DON'T PRINT OUT DATA TO SCREEN
    ;BEQ STARN
    LDA #$18
    JSR PRINT
    LDA #42  ; PRINT
    JSR PRINT
    JSR PRNTINPUT  ; PRINT STRING IN LABEL BUFFER
    JSR PRNTCR  ; PRINT CARRIAGE RETURN
STARN: LDA HEXFLAG  ; IF HEX, THE ARGUMENT HAS ALREADY BEEN FIGURED
    BNE STARR  ; SO JUMP OVER THIS NEXT PART
    LDY #0
STAF: LDA LABEL,Y
    CMP #32
    BEQ STAF1
    INY
    JMP STAF  ; FIND NUMBER (BY LOOKING FOR THE BLANK: *= 15)
STAF1: INY
    STY TEMP  ; POINT TO ASCII NUMBER
    LDA #<LABEL
    CLC
    ADC TEMP
    STA TEMP
    LDA #>LABEL
    ADC #0
    STA TEMP+1
    JSR VALDEC  ; TRANSLATE ASCII NUMBER INTO INTEGER (IN RESULT)
STARR: LDA PASS  ; ON PASS 1, LEAVE DISK OBJECT FILE ALONE.
    BEQ STARRX
    LDA DISKFLAG  ; ON PASS 2, WE'VE GOT TO STUFF THE DISK OBJECT FILE
    BEQ STARRX  ; IF THE DISKFLAG IS UP (WE ARE CREATING AN OBJECT CODE FILE)
    JSR FILLDISK  ; FILLDISK DOES THIS FOR US.
STARRX: LDA RESULT  ; PUT THE ARGUMENT OF *= INTO THE PC (SA)
    STA SA
    LDA RESULT+1
    STA SA+1
    PLA  ; PULL OFF THE RTS AND
    PLA
    JMP STARTLINE  ; RETURN TO EVAL FOR THE NEXT LINE OF CODE
    ;------------------ IS THIS THE END OF THE ENTIRE SOURCE CODE
ENDPRO: STA LABEL,Y  ; PUT THE ZERO (THAT SENT US HERE) INTO THE MAIN BUFFER
    INY
    CPY #80
    BNE ENDPRO  ; FILL REST OF BUFFER WITH 00S
    STA LABEL,Y
    JSR CHARIN  ; PULL IN THE NEXT 2 BYTES. IF THEY ARE BOTH ZEROS, THEN
    JSR CHARIN  ; WE HAVE, IN FACT, FOUND THE END OF OUR SOURCE CODE FILE
    BEQ INEND  ; AND WE BEQ TO INEND
    LDA #0  ; OTHERWISE WE PUT THE COLFLAG (COLON) DOWN, BECAUSE THIS IS
    STA COLFLAG  ; AN END OF LINE CONDITION, NOT A COLON
    RTS  ; AND RETURN TO CALLER
INEND: LDA #1  ;-------- SET END OF SOURCE CODE FILE FLAG TO UP CONDITION
    STA ENDFLAG
    RTS  ; AND RETURN TO CALLER
    ;------------------------ CHANGE A HEX NUMBER TO A 2-BYTE INTEGER
    ; PULL IN NEXT FEW BYTES, TURNING THEM INTO AN INTEGER IN RESULT
HEX: LDX #0  ; PUTS INTEGER EQUIVALENT OF INCOMING HEX INTO RESULT
H1: JSR CHARIN
    BEQ DECI  ; END OF LINE (SO STOP LOOKING)
    CMP #58
    BEQ DECI  ; COLON (SO STOP LOOKING)
    CMP #32
    BEQ H1  ; BLANK CHARACTER SO KEEP LOOKING FOR END OF LINE
    CMP #59
    BEQ DECI  ; SEMICOLON (SO STOP LOOKING)
    CMP #44
    BEQ DECIT  ; COMMA (SO STOP LOOKING, BUT GO TO A DIFFERENT PLACE)
    CMP #41  ; (THIS "DIFFERENT PLACE" HANDLES A NOT-END-OF-LINE CONDITION).
    BEQ DECIT  ; CLOSE PARENTHESIS ) (SO STOP LOOKING)
    STA HEXBUF,X  ; OTHERWISE, PUT THE ASCII-STYLE-HEX CHAR. IN BUFFER AND
    INX  ; RAISE THE INDEX AND
    STA LABEL,Y  ; ALSO STORE IT INTO MAIN BUFFER FOR PRINTOUT AND
    INY  ; RAISE THIS INDEX TOO
    JMP H1  ; THEN KEEP ON PUTTING HEX NUMBER INTO HEXBUFFER-----------
DECIT: STX HEXLEN  ; SAVE LENGTH OF ASCII-HEX NUMBER
    STA LABEL,Y  ; FINISH STORING CHARS. INTO MAIN BUFFER (, OR ) IN THIS CASE)
    INY
    JSR STARTHEX  ; TRANSLATE ASCII-HEX NUMBER INTO INTEGER IN RESULT VARIABLE
    JMP STINDISK  ; RETURN TO PULL IN REST OF THE LINE;-----------
DECI: STA VARA  ; SAVE THE END OF LINE, COLON, OR SEMICOLON CHAR. FOR LATER
    LDA #0
    STX HEXLEN  ; SAVE LENGTH OF ASCII-HEX NUMBER
    STA LABEL,Y  ; FINISH STORING CHARS. INTO MAIN BUFFER (0 IN THIS CASE)
    JSR STARTHEX  ; TRANSLATE ASCII-HEX NUMBER INTO INTEGER IN RESULT VARIABLE
    LDA VARA  ; RETRIEVE 0 OR COLON OR SEMICOLON AND GO BACK UP TO MOINDI WHICH
    JMP MOINDI  ;----------------- BEHAVES ACCORDING TO WHICH SYMBOL A HOLDS.
STARTHEX: LDA #0  ;----------------- HEX-ASCII TO INTEGER TRANSLATOR------
    STA RESULT  ; SET RESULT TO ZERO
    STA RESULT+1
    TAX  ; SET X TO ZERO
HXLOOP: ASL RESULT  ; SHIFT AND ROLL (MOVES 2-BYTE BITS TO THE LEFT) -----
    ROL RESULT+1  ; DOING THIS 8 TIMES HAS THE EFFECT OF BRINGING IN
    ASL RESULT  ; THE ASCII NUMBER, 1 BYTE AT A TIME, AND TRANSFORMING IT
    ROL RESULT+1  ; INTO A 2-BYTE INTEGER WITHIN THIS 2-BYTE VARIABLE WE'RE
    ASL RESULT  ; CALLING "RESULT."
    ROL RESULT+1
    ASL RESULT
    ROL RESULT+1
    LDA HEXBUF,X  ; GET A BYTE FROM THE ASCII-HEX NUMBER
    CMP #65  ; IF IT'S LOWER THAN 65, IT'S NOT AN ALPHABETIC (A-F) HEX NUMBER
    BCC HXMORE  ; SO DON'T SUBTRACT 7 FROM IT
    SBC #7  ; BUT IF IT'S > 65, THEN -7.    = 65. 65-7 = 58.
HXMORE: AND #15  ; WHEN YOU 58 AND 15, YOU GET 10 (THE VALUE OF A)
    ORA RESULT  ; #15 (00001111) AND #58 (00111010) = 00001010 (TEN)
    STA RESULT  ; PUT THE BYTE INTO RESULT
    INX  ; RAISE THE INDEX
    CPX HEXLEN  ; ARE WE AT THE END OF OUR ASCII-HEX NUMBER
    BNE HXLOOP  ; IF NOT, CONTINUE
    INC HEXFLAG  ; IF SO, RAISE HEXFLAG (TO SHOW RESULT HAS THE ANSWER)
    LDA #1  ; AND RETURN TO CALLER
    RTS
    ;-----------------------
    ; HANDLE PSEUDOS. (.BYTE TYPES)
PSEUDOJ: CPY #0  ; IF Y = 0 THEN IT'S NOT A PC LABEL LIKE (LABEL BYTE 0 0)
    BEQ PSE2
    LDX PASS  ; OTHERWISE, ON 1ST PASS, STORE LABEL NAME AND PC ADDR. IN ARRAY
    BNE PSE2
    PHA  ; SAVE A AND Y REGISTERS
    TYA
    PHA
    JSR EQUATE  ; NAME AND PC ADDR. STORED IN ARRAY
    PLA  ; PULL OUT A AND Y REGISTERS (RESTORE THEM)
    TAY
    PLA
PSE2: STA LABEL,Y  ; STORE . CHAR.
    INY
    JSR CHARIN  ; GET CHAR. FOLLOWING THE PERIOD (.)
    STA LABEL,Y
    INY
    CMP #66  ; IS IT "B" FOR BYTE
    BNE PSEUD1  ; WASN'T BYTE
    LDA #0  ; RESET FLAG WHICH WILL DISTINGUISH BETWEEN BYTE 0 AND BYTE "A
    STA BNUMFLAG  ; " TYPE, OR 00 08 15 172 TYPE (THE TWO BYTE TYPES)
    LDA PASS  ; PRINT NOTHING TO SCREEN ON PASS 1
    BEQ CLB
    STY VARY  ; SAVE Y REGISTER (OUR INDEX)
    ;        NOW WE REPLICATE THE ACTIONS OF INLINE (IN EVAL)
    LDA SFLAG  ; SHOULD WE PRINT TO SCREEN
    BEQ CLB  ; NO
    JSR PRNTLINE  ; YES, PRINT LINE NUMBER
    JSR PRNTSPACE  ; PRINT SPACE
    JSR PRNTSA  ; PRINT PC ADDRESS
    JSR PRNTSPACE  ; PRINT SPACE
    LDY VARY  ; RECOVER Y INDEX
CLB: JSR CHARIN  ; PULL IN CHARACTER FROM DISK/RAM
    STA LABEL,Y  ; STORE IN MAIN BUFFER
    INY
    CMP #32  ; IS IT A SPACE
    BNE CLB  ; IF NOT, CONTINUE PULLING IN MORE CHARACTERS------------
    JSR CHARIN  ; (WE'RE LOOKING FOR THE 1ST SPACE AFTER BYTE)
    STA LABEL,Y  ; STORE FOR PRINTING
    INY
    CMP #34  ; IS THE CHARACTER A QUOTE    IF SO, IT'S A BYTE "ABCD TYPE
    BNE BNUMWERK  ; OTHERWISE IT'S NOT THE " TYPE
BY1: JSR CHARIN  ;---------- HANDLE ASCII STRING BYTE TYPES
    BNE BY2
    JMP BENDPRO  ; FOUND A 0 END OF LINE (OR PROGRAM)
BY2: CMP #58  ; FOUND A COLON "END OF LINE"
    BNE BY2X
    JMP BEN1  ; FOUND A COLON
BY2X: CMP #59  ; FOUND A SEMICOLON "END OF LINE"
    BNE BY3
    JSR PULLREST  ; STORE COMMENTS IN COMMENT BUFFER (BABUF)
    LDX PRINTFLAG  ; IF NO PRINTOUT REQUESTED, THEN
    STX BABFLAG  ; DON'T PRINT COMMENTS
    JMP BENDPRO  ; A SEMICOLON SO END THIS ROUTINE IN THAT WAY.
BY3: CMP #34  ; HAVE WE FOUND A CONCLUDING QUOTE (")
    BNE BY3X
    JMP BY1  ; FOUND A " SO IGNORE IT
BY3X: LDX PASS  ; ON PASS 1, JUST RAISE PC COUNTER (INCSA); DON'T POKE IT.
    BNE PSLOOP
    JSR INCSA
    JMP BY1  ;-----------------
PSEUD1: JMP PSEUDO  ; SOME OTHER PSEUDO TYPE, NOT BYTE (A SPRINGBOARD)
PSLOOP: STA LABEL,Y  ; STORE A CHARACTER IN MAIN BUFFER;------------
    TAX
    STY VARY  ; SAVE Y INDEX
    JSR POKEIT  ; PASS 2, SO POKE IT INTO MEMORY (THE ASCII CHARACTER)
    LDY VARY  ; RESTORE Y
    INY  ; RAISE INDEX AND
    JMP BY1  ; GET NEXT CHARACTER
BNUMWERK: LDX #0  ;-------- HANDLE BYTE 1 2 3 (NUMERIC TYPE)
    STX BFLAG  ; PUT DOWN BFLAG (END OF LINE SIGNAL)
    STA NUBUF,X  ; WE'RE BORROWING THE NUBUF FOR THIS ROUTINE.
    INX
WERK1: LDA BFLAG  ; IF BFLAG IS UP, WE'RE DONE.
    BNE BBEND  ; SO GO TO END ROUTINE
WK0: JSR CHARIN  ; OTHERWISE, GET A CHARACTER FROM DISK/RAM
    BEQ BSFLAG  ; IF ZERO (END OF LINE) SET BFLAG UP.
    CMP #58  ; LIKEWISE IF COLON
    BEQ BSFLAG
    CMP #59  ; SEMICOLON REQUIRES THAT WE FIRST FILL THE COMMENT BUFFER
    BNE WK1  ;    BEFORE SETTING THE BFLAG (IN THE BSFLAG ROUTINE)
    JSR PULLREST  ; HERE'S WHERE THE COMMENT BUFFER IS FILLED
    LDX PRINTFLAG  ; IF NO PRINTOUT REQUESTED, THEN
    STX BABFLAG  ; DON'T PRINT COMMENTS
    JMP BSFLAG  ; FOUND SEMICOLON
WK1: STA BUFM  ; PUT CHAR. INTO "BUFM" BUFFER
    LDA PASS  ; ON PASS 1, RAISE THE PC ONLY (INCSA), NO POKES
    BNE WERK5
    LDA BUFM
    CMP #32  ; IS IT A SPACE
    BNE WERK1  ; IF NOT, RETURN FOR MORE OF THE NUMBER (0 VS 555)
    JSR INCSA  ; RAISE PC COUNTER BY 1
    JMP WERK1  ; GET NEXT NUMBER
WERK5: LDA BUFM  ; PUT CHAR. INTO PRINTOUT MAIN BUFFER
    STA LABEL,Y
    INY
    CMP #32  ; IS IT A SPACE
    BEQ WERK2
    CMP #0  ; IS IT END OF LINE
    BEQ WERK2
    CMP #58  ; IS IT COLON
    BEQ WERK2
    STA NUBUF,X  ; OTHERWISE, STORE IT
    INX
    JMP WERK1  ; AND RETURN FOR MORE OF THE NUMBER----------------
BSFLAG: INC BFLAG  ; RAISE UP THE END OF LINE FLAG
    STA BUFM+1  ; SAVE COLON, SEMICOLON, OR WHATEVER FOR LATER USE
    JMP WK1  ; RETURN FOR MORE (BUT THIS TIME IT WILL END LINE);---------
WERK2: LDA #<NUBUF  ; POINT TO THE ASCII NUMBER STORED IN BABUF
    STA TEMP
    LDA #>NUBUF
    STA TEMP+1
    STY VARY
    JSR VALDEC  ; TURN THE ASCII INTO AN INTEGER IN RESULT
    LDX RESULT
    JSR POKEIT  ; POKE THE RESULT INTO MEMORY (OR DISK OBJECT FILE)
    LDY VARY  ; ERASE THE NUMBER IN HEXBUF
    LDA #0
    LDX #5
CLEX: STA NUBUF,X
    DEX
    BNE CLEX
    JMP WERK1  ; AND THEN RETURN TO FETCH THE NEXT NUMBER;--------------
BBEND: LDA PASS  ; END BYTE LINE. ON PASS 1, RAISE PC (POKEIT RAISES IT
    BNE BBEND1  ;    ON PASS 2).
    JSR INCSA
BBEND1: LDA BUFM+1  ; IF END OF LINE SIGNAL WAS A COLON, THEN
    CMP #58
    BEQ BEN1  ; DON'T LOOK FOR LINE NUMBER OR END OF SOURCE CODE FILE (ENDPRO)
BENDPRO: JSR ENDPRO
BEN1: STA COLFLAG  ; SET IT (COLON) OR NOT (ENDPRO RETURNS WITH 0 IN A)
    INC LOCFLAG  ; RAISE PRINT-A-PC-LABEL FLAG
    PLA  ; PULL RTS FROM STACK
    PLA
    LDA PASS  ; ON PASS 1, DON'T PRINT ANY COMMENTS
    BEQ NOPR
    LDA SFLAG  ; IF SCREENFLAG IS DOWN, DON'T PRINT ANY COMMENTS
    BEQ NOPR
    JMP PRMMFIN  ; BACK TO EVAL (WHERE COMMENTS ARE PRINTED)
NOPR: JMP STARTLINE  ; BACK TO EVAL (BYPASSING PRINTOUT)
    ;----------------------- FOR CHANGE OF PC
FILLDISK: LDA PASS  ; A CHANGE OF PC REQUIRES FILLING A DISK OBJECT FILE
    CMP #2  ;    WITH THE REQUISITE NUMBER OF BYTES TO MAKE UP FOR
    BNE FILLX  ;    THE ADVANCING OF THE PROGRAM COUNTER (PC)
    RTS  ; NOT AT START OF 3RD PASS (3RD PASS IS JUST BEFORE SHUT DOWN)
FILLX: JSR CLRCHN
    LDX #2
    JSR CHKOUT  ; PUT SPACERS IN DISKFILE FOR *_
    SEC  ; FIND OUT HOW MANY SPACERS TO SEND TO DISK BY SUBTRACTING:RESULT-SA
    LDA RESULT
    SBC SA
    STA WORK  ; ANSWER HELD IN "WORK" VARIABLE
    LDA RESULT+1
    SBC SA+1
    STA WORK+1
PUTSPCR: LDA #0
    JSR PRINT  ; PRINT SPACER TO DISK
    LDA WORK  ; LOWER WORK BY 1
    BNE DECWORKX
    DEC WORK+1
DECWORKX: DEC WORK
    BNE PUTSPCR
    LDA WORK+1
    BNE PUTSPCR  ; PUT MORE SPACERS IN UNTIL "WORK" IS DECREMENTED TO ZERO.
RESFILL: JSR CLRCHN
    LDX #1  ; RESTORE NORMAL I/O
    JSR CHKIN
    RTS
    ;----------------------
KEYWAD: SEC  ; SEE KEYWORD ABOVE (SAME KEWORD TO ASCII STRING ROUTINE)
    SBC #$7F  ; THIS IS A VERSION OF KEYWORD, BUT FOR COMMENTS(PUTS IT IN BABUF
    STA KEYNUM  ;    INSTEAD OF LABEL BUFFER).
    LDX #255
SKEX: DEC KEYNUM
    BEQ FKEX
KSXX: INX
    LDA KEYWDS,X
    BPL KSXX
    BMI SKEX
FKEX: INX
    LDA KEYWDS,X
    BMI KSEX
    STA BABUF,Y
    INY
    JMP FKEX
KSEX: AND #$7F
    RTS
    ;------------------
    ; [LADS .FILE MATH]

; ---- module: math ----

    ; "MATH" THIS ROUTINE HANDLES +    IT COMES FROM EVAL AFTER INDISK
    ; IT LEAVES THE INTENDED ADDITION IN THE VARIABLE "ADDNUM"
    ; (ADDNUM IS ADDED TO "RESULT" IN THE VALDEC SUBPROGRAM)
MATH: LDY #0  ; SET INDEXES TO ZERO
    LDX #0
MATH1: LDA LABEL,Y  ; LOOK FOR LOCATION OF "+" SYMBOL--------
    CMP #43
    BEQ MATH2
    INY
    JMP MATH1  ;------------- NOW POINT TO 1ST NUMBER FOLLOWING +
MATH2: INY
    LDA LABEL,Y
    JSR RANGECK  ; CHECK TO SEE IF THIS IS BETWEEN 48 - 58 (ASCII FOR 0-9)
    BCS VALIT  ; IF NOT, EXIT THIS ROUTINE (WE'VE STORED THE NUMBER AND HAVE
    STA HEXBUF,X  ; LOCATED SOMETHING OTHER THAN AN ASCII NUMBER)
    INX  ; KEEP STORING VALID ASCII NUMBERS IN HEXBUF BUFFER
    JMP MATH2  ;-------------------
RANGECK: CMP #58  ;-------------- IS THIS >47 AND <58
    BCS MATH3
    SEC
    SBC #48
    SEC
    SBC #208  ; IS IT > 47 & < 58
MATH3: RTS
VALIT: LDA #0  ;---------- TURN IT FROM ASCII INTO A 2-BYTE INTEGER
    STA HEXBUF,X  ; PUT ZERO AT END OF ASCII NUMBER (AS DELIMITER)
    LDA #<HEXBUF  ; POINT "TEMP" POINTER TO ASCII NUMBER IN BUFFER
    STA TEMP
    LDA #>HEXBUF
    STA TEMP+1
    JSR VALDEC  ; ROUTINE WHICH TURNS ASCII NUMBER INTO INTEGER IN "RESULT"
    LDA RESULT  ; MOVE RESULT TO TEMPORARY ADDITION VARIABLE, "ADDNUM"
    STA ADDNUM
    LDA RESULT+1
    STA ADDNUM+1
    RTS  ; RETURN TO CALLER
    ; [LADS .FILE PRINTOPS]

; ---- module: printops ----

    ; "PRINTOPS"    PRINTS & POKES VALUES (BOTH OPCODES & ARGUMENTS)
FORMAT: LDA PASS  ; ON PASS 2, IGNORE INCSA (RAISES PC) SINCE
    BNE PRM  ; ON PASS 2, WE JSR TO POKEIT (IT GOES TO INCSA)
    JSR INCSA  ; BUT ON PASS 1, WE DON'T PRINT OR POKE ANYTHING, WE JUST
    RTS  ; RAISE THE PC AND RETURN --------------
PRM: LDA SFLAG  ; SHOULD WE PRINT TO SCREEN
    BEQ PRMX  ; IF NOT, SKIP THIS NEXT PART (PRINT TO SCREEN)
    JSR CLRCHN  ; OTHERWISE, RESET NORMAL I/O CONDITION
    LDX #1  ; (FILE #1 FOR INPUT, SCREEN FOR OUTPUT)
    JSR CHKIN
    LDX OP  ; LOAD THE OPCODE
    JSR PRNTNUM  ; PRINT IT
    JSR PRNTSPACE  ; PRINT A SPACE
PRMX: LDX OP  ;----------- NOW POKE THE OPCODE INTO RAM/DISK MEMORY
    JSR POKEIT
    RTS  ;---------------------------------------
    ; PRINT TWO BYTES (THE OPCODE AND A 1-BYTE ARGUMENT) -----------------
PRINT2: LDA PASS  ; ON PASS 2, WE SKIP INCSA (SEE LINE 20 ABOVE)
    BNE P2M
    JSR INCSA
    RTS  ;--------------------
P2M: LDA SFLAG  ; IF SCREEN PRINT FLAG IS DOWN, SKIP PRINTING TO SCREEN
    BEQ P2MX
    LDX RESULT  ; OTHERWISE PRINT THE LOW-BYTE OF "RESULT" (THE ARGUMENT)
    JSR PRNTNUM
P2MX: LDX RESULT  ; AND ALSO POKE THE LOW-BYTE TO RAM/DISK MEMORY
    JMP POKEIT  ; A JMP TO POKEIT WILL RTS US BACK TO THE CALLER------------
    ; PRINT THREE BYTES (THE OPCODE AND A 2-BYTE ARGUMENT) -----------------
PRINT3: LDA PASS  ; ON PASS 2, SKIP INCSA (SEE LINE 20 ABOVE)
    BNE P3M
    JSR INCSA  ; RAISE PC BY 2
    JSR INCSA
    RTS  ;--------------------
P3M: LDA SFLAG  ; SHOULE WE PRINT TO SCREEN
    BEQ P3MX
    LDX RESULT  ; PRINT AND POKE LOW BYTE OF ARGUMENT
    JSR PRNTNUM
P3MX: LDX RESULT
    JSR POKEIT
    LDA SFLAG  ; SHOULD WE PRINT TO SCREEN
    BEQ P3MXX
    LDA HXFLAG  ; ARE WE PRINTING OPCODES AND ARGUMENTS IN HEX
    BEQ P3MX2  ; IF SO, DON'T PRINT A SPACE HERE
    JSR PRNTSPACE  ; OTHERWISE, PRINT A SPACE
P3MX2: LDX RESULT+1  ; PRINT AND POKE THE HIGH BYTE OF THE ARGUMENT
    JSR PRNTNUM
P3MXX: LDX RESULT+1
    JMP POKEIT  ; AND A JUMP TO POKEIT WILL RTS US BACK TO CALLER
POKEIT: STX WORK+1  ;------------- POKE IN A BYTE TO RAM/DISK---------------
    LDA POKEFLAG  ; ARE WE SUPPOSED TO POKE TO RAM
    BEQ DISP  ; IF NOT, SKIP IT
    LDY #0  ; OTHERWISE, SEND THE BYTE TO RAM MEMORY AT CURRENT PC ADDRESS (SA)
    TXA
    STA (SA),Y  ;----------------
DISP: LDA DISKFLAG  ; ARE WE SUPPOSED TO POKE TO A DISK OBJECT FILE
    BEQ INCSA  ; IF NOT, SKIP IT
    JSR CLRCHN  ; IF SO, ALERT FILE #2 (WRITE FILE ON DISK)
    LDX #2
    JSR CHKOUT
    LDA WORK+1  ; PUT THE BYTE TO BE SENT TO DISK IN THE A REGISTER
    JSR PRINT  ; PRINT (AFTER LINES 550-570 ABOVE) PRINTS TO DISK FILE #2
    JSR CLRCHN  ; RESTORE NORMAL I/O (PRINT TO SCREEN AND
    LDX #1  ; READ FROM FILE #1
    JSR CHKIN
INCSA: CLC  ;------------------- RAISE THE PC COUNTER (SA) BY 1 --------
    LDA #1
    ADC SA
    STA SA
    LDA #0
    ADC SA+1
    STA SA+1
    RTS
    ;------------------------ PRINTOUT ROUTINES (TO SCREEN) ----------
PRNTMESS: LDY #0  ; PRINT A MESSAGE (ERRORS USUALLY) TO THE SCREEN
MESSLOOP: LDA (TEMP),Y  ; THESE MESSAGES ARE DELIMITED BY 0 AND ARE POINTED
    BEQ MESSDONE  ; TO BY THE VARIABLE "TEMP"
    JSR PRINT
    JSR PTP  ; AFTER PRINTING A CHARACTER TO SCREEN, CHECK TO SEE IF IT SHOULD
    INY  ;    ALSO BE PRINTED TO THE PRINTER
    JMP MESSLOOP
MESSDONE: RTS  ;----------------------------
PRNTSPACE: LDA #32  ; PRINT A SPACE CHARACTER
    JSR PRINT
    JSR PTP  ; SEE IF IT SHOULD ALSO GO TO THE PRINTER
    RTS  ;---------------------------------------------
PRNTNUM: STX VARX  ; PRINT A NUMBER (LOW BYTE IN X, HIGH BYTE IN A)
    LDA HXFLAG  ; IF WE'RE PRINTING IN HEX, NOT DECIMAL, THEN
    BEQ PRNTNUMD  ; USE THE HEXPRINT SUBROUTINE. OTHERWISE, GO TO PRNTNUMD
    TXA
    JSR HEXPRINT
    JSR PTPNU  ; CHECK IF NUMBER SHOULD BE PRINTED TO PRINTER AS WELL
    LDX VARX  ; RESTORE NUMBER IN X BEFORE
    RTS  ; RETURNING TO CALLER-------------------------
PRNTNUMD: LDA #0  ; PRINT A DECIMAL NUMBER
    JSR OUTNUM  ; BASIC'S LINE NUMBER PRINTOUT ROUTINE
    JSR PTPNU  ; SHOULD WE ALSO PRINT IT TO PRINTER
    LDX VARX  ; RESTORE VALUE IN X BEFORE
    RTS  ; RETURNING TO THE CALLER ----------------------------------
PRNTSA: LDA HXFLAG  ; PRINT THE SA (PC, PROGRAM COUNTER)
    BEQ PRNTSAD  ; IF NOT HEX PRINTOUT, THEN USE DECIMAL ROUTINE BELOW
    LDA SA+1  ; OTHERWISE, PRINT LOW AND HIGH BYTES OF SA (AS HEX)
    JSR HEXPRINT  ; HIGH BYTE 1ST
    LDA SA
    JSR HEXPRINT
    JSR PTPSA  ; SHOULD WE ALSO PRINT SA TO PRINTER
    RTS  ;----------------
PRNTSAD: LDX SA  ; PRINT SA (DECIMAL VERSION)
    LDA SA+1
    JSR OUTNUM
    JSR PTPSA  ; PRINT TO PRINTER, TOO
    RTS  ;-------------------------------------------------
PRNTCR: LDA #13  ;    PRINT A CARRIAGE RETURN
    JSR PRINT
    JSR PTP  ; SHOULD WE DO IT ON THE PRINTER TOO
    RTS  ;------------------------------------------------
PRNTLINE: LDX LINEN  ;    PRINT A SOURCE CODE LINE NUMBER
    LDA LINEN+1
    JSR OUTNUM  ; BASIC ROUTINE (LOW BYTE IN X, HIGH IN A)
    JSR PTPLI  ; SHOULD WE ALSO PRINT LINE NUMBER TO PRINTER
    RTS  ; -----------------------------------------------
PRNTINPUT: LDA #<LABEL  ;    PRINT CONTENTS OF MAIN INPUT
    STA TEMP  ;    BUFFER ("LABEL")
    LDA #>LABEL  ; POINT "TEMP" TO THE BUFFER AND THEN
    STA TEMP+1
    JSR PRNTMESS  ; USE GENERAL MESSAGE PRINTING ROUTINE
    RTS
    ;------------------------    ERROR PRINTOUT PREPARATIONS
ERRING: LDA #7  ; RING BELL
    JSR PRINT
    LDA #18  ; TURN ON REVERSE PRINTING TO HIGHLIGHT ERROR
    JSR PRINT
    JSR PRNTINPUT  ; PRINT CONTENTS OF MAIN INPUT BUFFER
    LDA #13  ; PRINT A CARRIAGE RETURN
    JSR PRINT
    RTS
    ;------------------------------------- PRINTOUT (TO PRINTER)
    ;(PTP PRINTS A SINGLE CHARACTER TO THE PRINTER).
PTP: LDX PASS  ; ON PASS 1, DO NO PRINTING TO PRINTER
    BNE PTP1
    RTS
PTP1: LDX PRINTFLAG  ; IF PRINTFLAG IS DOWN, DO NOTHING, RETURN TO CALLER
    BNE MPTP
    RTS  ;---------
MPTP: STA VARA  ; SAVE CONTENTS OF ACCUMULATOR
    JSR CLRCHN  ; ALERT PRINTER
    LDX #4
    JSR CHKOUT
    LDA VARA  ; RECOVER A
    JSR PRINT  ; PRINT TO PRINTER
    JSR CLRCHN  ; RESTORE NORMAL I/O
    LDX #1
    JSR CHKIN
RETT: LDA VARA  ; RECOVER A
    RTS  ; RETURN TO CALLER
    ;--------------------    NUMBERS TO PRINTER
PTPNU: LDX PASS  ; SAME LOGIC AS LINES 1350+ ABOVE
    BNE PTPN1
    RTS
PTPN1: LDX PRINTFLAG
    BNE MPTPN
    RTS
MPTPN: JSR CLRCHN
    LDX #4
    JSR CHKOUT
    LDA HXFLAG  ; HEX OR DECIMAL MODE
    BEQ MPTPND
    LDA VARX
    JSR HEXPRINT
    JMP FINPTP
MPTPND: LDA #0
    LDX VARX
    JSR OUTNUM
FINPTP: JSR CLRCHN
    LDX #1
    JSR CHKIN
    RTS
    ;------------------ SA TO PRINTER
PTPSA: LDX PASS  ; SAME LOGIC AS LINES 1350+ ABOVE
    BNE PTPS1
    RTS
PTPS1: LDX PRINTFLAG
    BNE MPTPSA
    RTS
MPTPSA: JSR CLRCHN
    LDX #4
    JSR CHKOUT
    LDX HXFLAG  ; HEX OR DECIMAL PRINTOUT
    BEQ MPTPSAD
    LDA SA+1
    JSR HEXPRINT
    LDA SA
    JSR HEXPRINT
    JMP FINPTPSA
MPTPSAD: LDA SA+1
    LDX SA
    JSR OUTNUM
FINPTPSA: JSR CLRCHN
    LDX #1
    JSR CHKIN
    RTS
    ;------------------ LINE NUMBER TO PRINTER
PTPLI: LDX PASS  ; SAME LOGIC AS LINES 1350+ ABOVE
    BNE PTPL1
    RTS
PTPL1: LDX PRINTFLAG
    BNE MPTPL
    RTS
MPTPL: JSR CLRCHN
    LDX #4
    JSR CHKOUT
    LDA LINEN+1
    LDX LINEN
    JSR OUTNUM
    JSR CLRCHN
    LDX #1
    JSR CHKIN
    RTS
    ;---------------------------------- HEX NUMBER PRINTOUT
    ; PRINT THE NUMBER IN THE ACCUMULATOR AS A HEX DIGIT (AS ASCII CHARS.)
HEXPRINT: PHA  ; STORE NUMBER
    AND #$0F  ; CLEAR HIGH BITS (10101111 BECOMES 00001111, FOR EXAMPLE)
    TAY  ; NOW WE KNOW WHICH POSITION IN THE STRING OF HEX NUMBERS ("HEXA")
    LDA HEXA,Y  ; THIS NUMBER IS. SO PULL IT OUT AS AN ASCII CHARACTER
    ; (HEXA LOOKS LIKE THIS: "0123456789ABCDEF")
    TAX  ; SAVE LOW-BITS VALUE INTO X
    PLA  ; PULL OUT THE ORIGINAL NUMBER, BUT THIS TIME
    LSR  ;SHIFT RIGHT 4 TIMES (MOVING THE 4 HIGH BITS INTO THE 4 LOW BITS AREA)
    LSR  ; (10101111 BECOMES 00001010, FOR EXAMPLE)
    LSR
    LSR
    TAY  ; AGAIN, PUT POSITION OF THIS VALUE INTO THE Y INDEX
    LDA HEXA,Y  ; PULL OUT THE RIGHT ASCII CHARACTER FROM "HEXA" STRING
    JSR PRINT  ; PRINT HIGH VALUE (FIRST) (A HOLDS HIGH VALUE AFTER LINE 2280)
    TXA  ; (X HELD LOW VALUE AFTER LINE 2210)
    JSR PRINT  ; PRINT LOW VALUE
    RTS  ; RETURN TO CALLER
    ; [LADS .FILE PSEUDO]

; ---- module: pseudo ----

    ; "PSEUDO" HANDLE ALL PSEUDOPS EXCEPT BYTE
    ;
    ; JMP HERE FROM INDISK
    ;    (INDISK WAS JSR'ED TO FROM EVAL . / Y HOLDS POINTER TO LABEL
    ; -------------------------
PSEUDO: CMP #70  ; IS IT "F" FOR FILE
    BNE PSE1
    JSR FILE  ; F MEANS GO TO NEXT LINKED FILE -----------------
GOBACK: PLA  ; RETURN TO EVAL TO GET NEXT LINE
    PLA
    JMP STARTLINE  ;------------------------
PSE1: CMP #128  ; IS IT END
    BNE PSEE
    JSR PEND  ; 128 IS TOKEN FOR END (END OF CHAIN PSEUDO)
    JMP GOBACK  ; RETURN TO EVAL
PSEE: CMP #68  ; IS IT "D" FOR DISK (CREATE OBJECT CODE FILE ON DISK)
    BNE PSEE1
    JMP PDISK  ; OPEN FILE ON DISK FOR OBJECT CODE STORAGE
PSEE1: CMP #80  ; IS IT "P" FOR P (PRINTER OUTPUT)
    BNE PSEE2
    JMP PRINTER  ; TURN ON PRINTER LISTING
PSEE2: CMP #78  ; IS IT "N" FOR NH OR NS OR SOME OTHER "TURN IT OFF"
    BNE PSEE3
    JMP NIX  ; TURN SOMETHING OFF
PSEE3: CMP #79  ; IS IT "O" FOR OUTPUT (POKE OBJECT CODE INTO RAM)
    BNE PSEE4
    JMP OPON  ; START POKING OBJECT CODE (DEFAULT)
PSEE4: CMP #83  ; IS IT "S" FOR PRINT TO SCREEN
    BNE PSEE5
    JMP SCRNOP  ; TURN ON SCREEN PRINTING
PSEE5: CMP #72  ; IS IT "H" FOR HEX NUMBERS DURING PRINTOUTS
    BNE PSE9  ;
    JMP HEXIT  ; TURN ON HEX PRINTING
    ;------------------------- PRINT ERROR MESSAGE (NO SUCH PSEUDO-OP)
PSE9: STA LABEL,Y  ; STORE CHAR. FOR PRINTOUT
    JSR PRNTLINE
    JSR PRNTSPACE
    JSR PRNTSA
    JSR ERRING
    JSR PRNTINPUT
    LDA #<MERROR
    STA TEMP
    LDA #>MERROR
    STA TEMP+1
    JSR PRNTMESS
    JSR PRNTCR
    JMP PULLINE  ; PULL IN (& IGNORE) REST OF LINE, THEN BACK TO EVAL
    ;------------------------- HANDLE FILE PSEUDO-OP ----------------
FILE: JSR CHARIN
    CMP #32  ; LOOK FOR END OF THE WORD FILE (TO LOCATE FILENAME)
    BEQ FIO
    JMP FILE  ; CONTINUE LOOKING FOR BLANK
FIO: LDY #0
FI1: JSR CHARIN
    CMP #0  ; END OF LINE
    BEQ FI2
    CMP #127  ; KEYWORD, SO STRETCH IT OUT
    BCC FII1
    JSR KEYWORD
FII1: STA LABEL,Y  ; STORE CHAR. OF FILENAME
    INY
    JMP FI1  ; CONTINUE STORING FILENAME IN MAIN BUFFER (LABEL)
FI2: STY FNAMELEN  ; STORE FILENAME LENGTH
    LDY #0
FILO: LDA LABEL,Y  ;------- PUT FILENAME INTO PROPER BUFFER (FILEN)
    BEQ FIL01
    STA FILEN,Y
    INY
    JMP FILO
FIL01: LDA PASS  ; ON PASS 2, DON'T PRINT OUT PC
    BNE FI5
    JSR PRNTSA  ; PRINT THE FILENAME
    JSR PRNTSPACE
FI5: JSR PRNTINPUT
    JSR PRNTCR  ; CARRIAGE RETURN
    JSR OPEN1  ; OPEN NEXT LINKED FILE ON DISK (FOR CONTINUED READING OF SOURCE)
    LDX #1
    JSR CHKIN
    JSR CHARIN  ; PULL IN NEXT TWO BYTES AND
    JSR CHARIN
    JSR ENDPRO  ; CHECK FOR END OF PROGRAM
    LDX #0
    STX ENDFLAG  ; SET END OF PROGRAM FLAG TO ZERO
    RTS
    ;------------------------- HANDLE END PSEUDO-OP ---------
PEND: LDA #46  ; PRINT OUT END
    JSR PRINT
    LDA #69
    JSR PRINT
    LDA #78
    JSR PRINT
    LDA #68
    JSR PRINT
    LDA #32
    JSR PRINT
    JSR CHARIN
    JSR FIO  ; GET FILENAME, ETC. JUST AS FILE PSEUDO-OP DOES
    LDA PASS  ; ON PASS 1, DON'T SET THE ENDFLAG UP.
    BEQ PEND1  ; BUT ON PASS 2, IT'S NECESSARY (TO END THE ENTIRE PROGRAM)
    INC ENDFLAG
PEND1: INC PASS  ; RAISE PASS FROM PASS 1 TO PASS 2
    LDA TA  ; PUT ORIGINAL START ADDRESS BACK INTO PC (SA) FOR RESTART OF
    STA SA  ; ASSEMBLY ON PASS 2.
    LDA TA+1
    STA SA+1
    JSR INDISK  ; SET UP NEXT LINE
    RTS
    ;------------------- HANDLE D FILENAME PSEUDO-OP (OBJECT CODE FILE)
PDISK: LDA PASS  ; ON PASS 1, DON'T STORE ANYTHING TO DISK
    BEQ PULLJ  ; PULL) IS A SPRINGBOARD (JUMPS TO PULLINE)
    JSR CHARIN  ; POINT TO FILENAME
    STA LABEL,Y
    LDY #0
PDLOOP: JSR CHARIN
    BEQ PD1  ; END OF LINE
    CMP #127  ; IT'S A KEYWORD (WITHIN THE FILENAME) IF >127
    BCC PDIX
    JSR KEYWORD
PDIX: STA LABEL,Y  ; KEEP STORING FILENAME INTO PRINTOUT BUFFER (LABEL)
    STA FILEN,Y  ; AS WELL AS OPEN1 BUFFER (FILEN)
    INY
    JMP PDLOOP  ; KEEP STORING FILENAME;------------------
PULLJ: JMP PULLINE  ;-------- SPRINGBOARD TO IGNORE FILENAME
PD1: LDA #44  ; PUT P,W (PROGRAM, WRITE) SIGNALS ONTO FILENAME
    STA FILEN,Y
    INY
    LDA #80
    STA FILEN,Y
    INY  ; ADD--,P,W
    LDA #44
    STA FILEN,Y
    INY
    LDA #87
    STA FILEN,Y
    INY
    STY FNAMELEN  ; STORE FILENAME LENGTH
    JSR PRNTINPUT  ; PRINT OUT THE LINE
    JSR PRNTCR  ; CARRIAGE RETURN
    INC DISKFLAG  ; RAISE DISKFLAG TO SHOW THAT FUTURE POKES SHOULD GO TO DISK
    JSR OPEN2  ; OPEN A SECOND DISK FILE (THIS ONE FOR WRITING TO)
    LDX #2
    JSR CHKOUT
    LDA TA  ; PRINT OBJECT CODE'S STARTING ADDRESS TO DISK FILE
    JSR PRINT
    LDA TA+1
    JSR PRINT
EDISK: JSR CLRCHN
    LDX #1  ; RESTORE NORMAL I/O
    JSR CHKIN
    JSR DISERR  ; CHECK FOR DISK ERROR (FAILURE TO OPEN CORRECTLY)
    JSR ENDPRO  ; GET NEXT LINE NUMBER
    PLA  ; PULL RTS
    PLA
    LDX #0
    STX ENDFLAG  ; RESET END OF PROGRAM FLAG
    JMP STARTLINE  ; AND RETURN TO EVAL TO GET NEXT LINE
    ;-------------------------- HANDLE .P (PRINTER) PSEUDO-OP -------
PRINTER: LDA PASS  ; ON PASS 1, DO NO PRINTER OUTPUT
    BEQ PULLINE  ; GET RID OF REST OF LINE AND GO ON.
    JSR OPEN4  ; PASS 2, SO OPEN PRINTER TO HEAR FROM COMPUTER
    INC PRINTFLAG  ; RAISE PRINTER OUTPUT FLAG (SO PRINT WILL SEND BYTES TO
    JSR CLRCHN  ;    THE PRINTER AS WELL AS THE SCREEN).
    LDX #1  ; RESTORE NORMAL I/O
    JSR CHKIN
    ;---------------------- SUCTION ROUTINE. GET RID OF REST OF A LINE
PULLINE: JSR CHARIN  ; IGNORE ALL BYTES, JUST LOCATE NEXT LINE
    BEQ ENDPULL  ; ZERO END OF LINE SHOULD GO TO ENDPRO FOR NEXT LINE #
    CMP #58  ; WHEREAS A COLON END OF LINE SKIPS THAT STEP
    BEQ ENDPULR  ; (COLON)
    JMP PULLINE  ; NEITHER COLON NOR ZERO (SO PULL IN MORE CHARACTERS)
ENDPULL: JSR ENDPRO
ENDPULR: PLA  ; PULL RTS OFF STACK
    PLA
    LDX #0
    STX ENDFLAG  ; SET ENDFLAG DOWN
    JMP STARTLINE  ; RETURN TO EVAL (TO GET NEXT LINE OF SOURCE CODE)
    ;-------------------------- HANDLE .O (POKE BYTES TO RAM) PSEUDO-OP
OPON: LDA #46  ; PRINT .O
    JSR PRINT
    LDA #79  ; "0"
    JSR PRINT
    JSR PRNTCR  ; CARRIAGE RETURN
    LDA #1
    STA POKEFLAG  ; RAISE POKE-TO-RAM FLAG
    JMP PULLINE  ; IGNORE REST OF LINE
    ;-------------------------- HANDLE .N(SOMETHING),TURN-IT-OFF PSEUDO-OPS
NIX: LDA PASS  ; ON PASS 1, DON'T BOTHER WITH ANY OF THIS
    BEQ PULLINE
    JSR CHARIN  ; ON PASS 2, SEE WHICH THING IS BEING TURNED OFF
    CMP #80  ; IS IT ".NP" TO "NOT PRINT TO PRINTER"
    BEQ NIXPRINT
    CMP #79  ; IS IT ".NO" TO "NOT POKE OBJECT BYTES TO RAM"
    BEQ NIXOP
    CMP #83  ; IS IT ".NS" TO "NOT PRINT TO SCREEN"
    BEQ NIXSCREEN
    CMP #72  ; IS IT ".NH" TO "NOT PRINTOUT HEX" (THUS SWITCH TO DECIMAL)
    BEQ NIXHEX
    ;-------------------------- TURN OFF PRINTER OUTPUT
NIXPRINT: LDA #46  ; PRINT ".NP" TO SCREEN
    JSR PRINT
    LDA #78  ; "N"
    JSR PRINT
    LDA #80  ; "P"
    JSR PRINT
    JSR PRNTCR  ; CARRIAGE RETURN
    DEC PRINTFLAG  ; LOWER PRINT-TO-SCREEN FLAG
    JSR CLRCHN  ; TURN OFF PRINTER
    LDX #4
    JSR CHKOUT
    LDA #13
    JSR PRINT
    LDA #4
    JSR CLOSE
    JSR CLRCHN
    LDX #1  ; RESTORE NORMAL I/O
    JSR CHKIN
    JMP PULLINE  ; IGNORE REST OF LINE (AND RETURN TO EVAL)
    ;-------------------------- STOP POKEING OBJECT BYTES TO RAM
NIXOP: LDA #46  ; PRINT ".NO"
    JSR PRINT
    LDA #78  ;    "N"
    JSR PRINT
    LDA #79  ;    "O"
    JSR PRINT
    JSR PRNTCR  ;CARRIAGE RETURN
    LDA #0
    STA POKEFLAG  ; TURN OFF POKE FLAG
    JMP PULLINE  ; IGNORE REST OF LINE (AND RETURN TO EVAL)
    ;-------------------------- STOP HEX PRINTOUTS (START DECIMAL)
NIXHEX: LDA #46  ; PRINT ".NH"
    JSR PRINT
    LDA #78  ;    "N"
    JSR PRINT
    LDA #72  ;    "H"
    JSR PRINT
    JSR PRNTCR  ; CARRIAGE RETURN
    LDA #0
    STA HXFLAG  ; PUT HEXFLAG DOWN
    JMP PULLINE  ; IGNORE REST OF LINE (AND RETURN TO EVAL)
    ;-------------------------- STOP SCREEN PRINTOUTS
NIXSCREEN: LDA #46  ; PRINT ".NS"
    JSR PRINT
    LDA #78  ;    "N"
    JSR PRINT
    LDA #83  ;    "S"
    JSR PRINT
    JSR PRNTCR  ;CARRIAGE RETURN
    LDA #0
    STA SFLAG  ; PUT DOWN SCREEN PRINTOUT FLAG
    JMP PULLINE  ; IGNORE REST OF LINE (AND RETURN TO EVAL)
    ;-------------------------- DISK ERROR DETECTION ROUTINE --------
DISERR: LDX ST  ; CHECK DISK STATUS VARIABLE (COMPUTER SPECIFIC)
    BNE MODIER  ; IF NOT ZERO, THERE IS SOME FAULT IN THE DISK I/O
    RTS  ;----------
MODIER: LDA #0  ; PRINT OUT ERROR MESSAGE
    JSR PRNTNUM
    JSR PRNTSPACE
    LDA #<MDISER
    STA TEMP  ; POINT TO DISK ERROR MESSAGE
    LDA #>MDISER
    STA TEMP+1
    JSR ERRING  ; RING BELL
    JSR PRNTMESS  ; PRINT ERROR MESSAGE
    PLA  ; PULL RTS OFF STACK
    PLA
    JMP FIN  ; SHUT DOWN ENTIRE LADS OPERATION
    ;--------------- HANDLE S PSEUDO-OP (TURN ON SCREEN PRINTOUT)
SCRNOP: LDA #46  ; PRINT ".S"
    JSR PRINT
    LDA #83  ;    "S"
    JSR PRINT
    JSR PRNTCR  ; CARRIAGE RETURN
    LDA PASS  ; ON PASS 1, NO SCREEN PRINTOUT
    BEQ SCREX
    LDA #1  ; OTHERWISE, RAISE SCREEN PRINTOUT (LISTING) FLAG
    STA SFLAG
SCREX: JMP PULLINE  ; IGNORE REST OF LINE (AND RETURN TO EVAL)
    ;-------------- HANDLE H PSEUDO-OP (HEX NUMBERS DURING PRINTOUT)
HEXIT: LDA #46  ; PRINT ".H"
    JSR PRINT
    LDA #72  ;    "H"
    JSR PRINT
    JSR PRNTCR  ; CARRIAGE RETURN
    LDA #1
    STA HXFLAG  ; SET HEXFLAG UP
    JMP PULLINE  ; IGNORE REST OF LINE (AND RETURN TO EVAL)
    ; [LADS .FILE TABLES]

; ---- module: tables ----

    ; "TABLES"
    ;
    ; TABLE OF MNEMONICS AND PARALLEL TABLE OF OPCODE/ADDRESS TYPE DATA
    ; BUFFERS AND MESSAGES, FLAGS, POINTERS, REGISTERS
    ;------------------------- MNEMONICS, TYPES, ADDRESS MODE OPCODES
MNEMONICS: .byte "LDALDYJSRRTSBCSBEQBCCCMP"
    .byte "BNELDXJMPSTASTYSTXINYDEY"
    .byte "DEXDECINXINCCPYCPXSBCSEC"
    .byte "ADCCLCTAXTAYTXATYAPHAPLA"
    .byte "BRKBMIBPLANDORAEORBITBVC"
    .byte "BVSROLRORLSRCLDCLIASLPHP"
    .byte "PLPRTISEDSEITSXTXSCLVNOP"
TYPES: .byte 1,5,9,0,8,8,8,1
    .byte 8,5,6,1,2,2,0,0
    .byte 0,2,0,2,4,4,1,0
    .byte 1,0,0,0,0,0,0,0
    .byte 0,8,8,1,1,1,7,8
    .byte 8,3,3,3,0,0,3,0
    .byte 0,0,0,0,0,0,0,0
OPS: .byte 161,160,32,96,176,240,144,193
    .byte 208,162,76,129,132,134,200,136
    .byte 202,198,232,230,192,224,225,56
    .byte 97,24,170,168,138,152,72,104
